/* EXAMEN GLOBAL: Todas las preguntas de ADIPLE */
const EXAM_DATA = [
// --- PREGUNTAS DE LA PLATAFORMA (MOODLE) ---
    { u: "ADIPLE T1", q: "¿Cuál de las siguientes no es una característica del préstamo hipotecario?", opts: ["La cuantía concedida dependerá del valor de la vivienda.", "Habitualmente la cuantía concedida no superará el 80% del valor de tasación.", "Su plazo máximo de amortización no suele exceder de 8 años.", "Suele utilizarse para la compra de bienes inmuebles."], ans: 2, exp: "Los préstamos hipotecarios se caracterizan precisamente por tener plazos de amortización muy largos, que habitualmente oscilan entre los 15 y los 30 años, debido a las altas sumas de dinero concedidas." },
    { u: "ADIPLE T1", q: "¿Cuál de los siguientes es un agente que actúa en la economía?", opts: ["Familias.", "Empresas.", "Estado.", "Todas con correctas."], ans: 3, exp: "La economía se basa en la interacción de tres agentes principales: las familias (consumo y trabajo), las empresas (producción) y el Estado (regulación y servicios públicos)." },
    { u: "ADIPLE T1", q: "¿En qué se basa la decisión que se toma para cubrir necesidades?", opts: ["En un impulso.", "En una comparativa.", "En una encuesta.", "En una imitación de lo que hace la sociedad."], ans: 1, exp: "En una economía racional, la toma de decisiones para cubrir necesidades se fundamenta en la comparación de alternativas, evaluando la relación coste-beneficio de cada opción." },
    { u: "ADIPLE T1", q: "¿Qué nombre recibe el valor que se le otorga a un bien en una fecha determinada?", opts: ["Liquidación.", "Subasta.", "Tasación.", "Presupuesto."], ans: 2, exp: "La tasación es la valoración oficial y técnica de un bien (normalmente inmueble) realizada por un experto para determinar su precio de mercado actual." },
    { u: "ADIPLE T1", q: "¿Qué nombre recibe la entidad que concede préstamos?", opts: ["Prestamista.", "Prestatario.", "Préstamo.", "Hipotecario."], ans: 0, exp: "El prestamista es la parte (banco o persona) que entrega el capital, mientras que el prestatario es quien lo recibe y tiene la obligación de devolverlo." },
    { u: "ADIPLE T1", q: "¿Qué nombre reciben las siglas I.T.A.S?", opts: ["Impuesto de Transmisiones Analógicas y Sucesiones.", "Impuesto de Trabajo y Actuaciones Sociales.", "Impuesto de Transmisiones Patrimoniales y Actos Jurídicos Documentados.", "Impuesto de Tráfico y Acciones Societarias."], ans: 2, exp: "El ITP y AJD es el impuesto que grava la compra de viviendas de segunda mano y la formalización de documentos notariales como las escrituras." },
    { u: "ADIPLE T1", q: "¿Qué significa que el sistema sea democrático en las cooperativas?", opts: ["Que manda el que tiene más dinero.", "Cada persona tiene un voto, independientemente de su capital aportado.", "Manda el Estado.", "Deciden solo los fundadores."], ans: 1, exp: "A diferencia de las Sociedades Anónimas donde el voto depende de las acciones, en las cooperativas impera el principio de gestión democrática: un socio equivale a un voto." },
    { u: "ADIPLE T1", q: "El F.I.P.E.R es un documento:", opts: ["Para comprar comida.", "Informativo sobre las condiciones de un préstamo hipotecario.", "De identidad.", "Para pagar impuestos."], ans: 1, exp: "La Ficha de Información Personalizada (FIPER) es un documento obligatorio que el banco entrega al cliente detallando todas las condiciones específicas de su futura hipoteca." },
    { u: "ADIPLE T1", q: "La sigla S.A representa a:", opts: ["Sociedad Anónima.", "Sociedad Amiga.", "Sistemas Automáticos.", "Sustancia Ambiental."], ans: 0, exp: "La Sociedad Anónima es una forma jurídica de empresa donde el capital está dividido en acciones y los socios no responden personalmente de las deudas sociales." },
    { u: "ADIPLE T1", q: "Las necesidades secundarias son aquellas:", opts: ["Indispensables para sobrevivir.", "Que aumentan el bienestar pero no son vitales.", "Que solo tienen los ricos.", "Que no cuestan dinero."], ans: 1, exp: "Mientras que las primarias son biológicas (comer, dormir), las secundarias son culturales o sociales, como viajar o tener un teléfono de última generación." },

    // --- BLOQUE CUESTIONARIO DE AUTOEVALUACIÓN (70 PREGUNTAS) ---
    { u: "ADIPLE T1", q: "¿Qué estudia la economía fundamentalmente?", opts: ["Cómo fabricar oro.", "La administración de recursos escasos para satisfacer necesidades humanas.", "Solo el funcionamiento de los bancos.", "La historia de las monedas antiguas."], ans: 1, exp: "La economía nace de la escasez: los recursos son limitados pero las necesidades humanas son infinitas, por lo que hay que elegir cómo usarlos." },
    { u: "ADIPLE T1", q: "El 'Coste de Oportunidad' se define como:", opts: ["El precio de un producto en oferta.", "Aquello a lo que renunciamos al elegir una opción sobre otra.", "El coste de envío de un paquete.", "La multa por pagar tarde."], ans: 1, exp: "Toda elección implica una renuncia. El coste de oportunidad de estudiar es el salario que dejas de ganar por no estar trabajando en ese tiempo." },
    { u: "ADIPLE T1", q: "¿Cuál es un bien 'Económico' según el temario?", opts: ["El aire que respiramos.", "Un coche.", "La luz del sol.", "El agua del mar."], ans: 1, exp: "Los bienes económicos son escasos, tienen un precio y requieren un proceso de producción, a diferencia de los bienes libres (como el aire)." },
    { u: "ADIPLE T1", q: "Las familias en el sistema económico tienen la función de:", opts: ["Legislar sobre el comercio.", "Consumir bienes y servicios y ofrecer su trabajo.", "Fabricar materias primas únicamente.", "Cobrar impuestos a las empresas."], ans: 1, exp: "Las familias son las unidades básicas de consumo y los propietarios de los factores de producción (especialmente el trabajo)." },
    { u: "ADIPLE T1", q: "¿Cuál es el objetivo principal de una empresa privada?", opts: ["Maximizar el beneficio económico.", "Perder dinero para ayudar a otros.", "No tener trabajadores.", "Limpiar la ciudad únicamente."], ans: 0, exp: "La finalidad última de la empresa privada en el sistema capitalista es la obtención de rédito económico mediante su actividad." },
    { u: "ADIPLE T1", q: "El Estado interviene en la economía para:", opts: ["Prohibir el consumo de las familias.", "Redistribuir la renta y proporcionar servicios públicos básicos.", "Quedarse con todas las empresas.", "Fijar el precio de todos los productos."], ans: 1, exp: "El sector público corrige fallos del mercado y garantiza educación, sanidad y justicia mediante la recaudación de impuestos." },
    { u: "ADIPLE T1", q: "¿Qué es el 'Mercado'?", opts: ["Un edificio físico únicamente.", "Cualquier mecanismo donde compradores y vendedores acuerdan precios.", "Una lista de la compra.", "El almacén de una fábrica."], ans: 1, exp: "Hoy en día el mercado puede ser físico o digital (e-commerce); es el punto de encuentro abstracto de la oferta y la demanda." },
    { u: "ADIPLE T1", q: "La Ley de la Demanda indica que, si sube el precio de un bien:", opts: ["La gente compra más.", "La cantidad demandada disminuye.", "La demanda se queda igual.", "El Estado lo regala."], ans: 1, exp: "Existe una relación inversa: normalmente, cuanto más caro es algo, menos gente está dispuesta o puede permitirselo." },
    { u: "ADIPLE T1", q: "¿Qué es la 'Inflación'?", opts: ["Cuando los globos se hinchan.", "El aumento generalizado y sostenido de los precios.", "La bajada de los salarios.", "El nombre de una moneda."], ans: 1, exp: "La inflación reduce el poder adquisitivo: con el mismo billete de 20 euros, cada año puedes comprar menos cosas." },
    { u: "ADIPLE T1", q: "Una 'Sociedad Limitada' (S.L.) se caracteriza por:", opts: ["Tener socios ilimitados.", "Responsabilidad limitada al capital aportado por los socios.", "No poder tener beneficios.", "Funcionar sin estatutos."], ans: 1, exp: "Es la forma más común para pymes, ya que protege el patrimonio personal de los socios ante posibles deudas de la empresa." },
    { u: "ADIPLE T1", q: "El capital mínimo legal para constituir una Sociedad Anónima es de:", opts: ["3.000 euros.", "60.000 euros.", "1 euro.", "No hay mínimo."], ans: 1, exp: "La S.A. requiere una inversión inicial mayor debido a su enfoque para grandes empresas y salida a bolsa." },
    { u: "ADIPLE T1", q: "¿Qué es un 'Empresario Individual' o Autónomo?", opts: ["Una persona física que ejerce una actividad por cuenta propia de forma habitual.", "Un trabajador de una gran multinacional.", "Un robot de inteligencia artificial.", "Un funcionario del Estado."], ans: 0, exp: "El autónomo gestiona su propio negocio y responde de las deudas con todo su patrimonio presente y futuro." },
    { u: "ADIPLE T1", q: "En el organigrama de una empresa, el Staff se refiere a:", opts: ["Los trabajadores de la fábrica.", "Asesores externos o especialistas que apoyan a la dirección.", "Los clientes habituales.", "El personal de limpieza."], ans: 1, exp: "Son departamentos de apoyo (como asesoría jurídica o auditoría) que no están en la línea directa de mando jerárquico." },
    { u: "ADIPLE T1", q: "La 'Financiación Propia' de una empresa proviene de:", opts: ["Préstamos bancarios.", "Aportaciones de los socios y beneficios no repartidos (reservas).", "Hacer trampas.", "Subvenciones del ayuntamiento."], ans: 1, exp: "Es el dinero que pertenece a la empresa y no tiene que devolverse a terceros externos." },
    { u: "ADIPLE T1", q: "¿Qué es un 'Activo' en el balance de una empresa?", opts: ["Lo que la empresa debe a los bancos.", "Los bienes, derechos y recursos que posee la empresa.", "Los impuestos a pagar.", "La opinión de los clientes."], ans: 1, exp: "Incluye desde el dinero en caja y las facturas pendientes de cobro hasta la maquinaria y las furgonetas." },
    { u: "ADIPLE T1", q: "El 'Pasivo' representa:", opts: ["Los coches de la empresa.", "Las deudas y obligaciones financieras con terceros.", "El nombre de los socios.", "Las ventas del mes."], ans: 1, exp: "Es el origen de los fondos; nos indica cómo ha financiado la empresa sus activos (debiendo dinero o usando capital propio)." },
    { u: "ADIPLE T1", q: "¿Para qué sirve un 'Presupuesto'?", opts: ["Para gastar dinero sin control.", "Para planificar y controlar los ingresos y gastos previstos.", "Es solo un papel decorativo.", "Para pedir permiso al Estado."], ans: 1, exp: "Es la herramienta maestra de gestión: permite anticipar cuánto dinero entrará y cuánto se puede gastar sin entrar en quiebra." },
    { u: "ADIPLE T1", q: "Un 'Préstamo Personal' suele utilizarse para:", opts: ["Comprar una casa.", "Consumo de bienes duraderos (ej. un coche, una reforma).", "Pagar el pan diario.", "Invertir en la bolsa americana."], ans: 1, exp: "Son créditos de cuantía media con intereses superiores a la hipoteca y garantías basadas en la nómina del solicitante." },
    { u: "ADIPLE T1", q: "¿Qué es el T.A.E.?", opts: ["Tasa de Ahorro Externo.", "Tasa Anual Equivalente (coste real del préstamo incluyendo intereses y comisiones).", "Tiempo de Amortización Estándar.", "Total de Activos de la Empresa."], ans: 1, exp: "Es el indicador más fiable para comparar bancos, ya que incluye no solo el interés nominal sino también los gastos de apertura y comisiones." },
    { u: "ADIPLE T1", q: "La 'Amortización' técnica de una máquina es:", opts: ["Venderla.", "Reflejar el desgaste y pérdida de valor de la máquina por el uso y el tiempo.", "Comprar una nueva.", "Pintarla."], ans: 1, exp: "Contablemente, cada año la máquina vale menos; la amortización permite guardar dinero para comprar el repuesto cuando se rompa por vieja." },
    { u: "ADIPLE T1", q: "¿Cuál es la función del Registro Mercantil?", opts: ["Guardar las llaves de las fábricas.", "Dar publicidad legal a la constitución y actos de las sociedades.", "Vender productos rebajados.", "Hacer encuestas de mercado."], ans: 1, exp: "Es el registro oficial donde se inscriben las empresas para que cualquiera pueda comprobar quiénes son sus administradores y sus cuentas anuales." },
    { u: "ADIPLE T1", q: "El 'Capital Social' es:", opts: ["El dinero que la empresa da a ONGs.", "La cifra escriturada que los socios han aportado a la sociedad.", "Los impuestos pagados en un año.", "La suma de los sueldos."], ans: 1, exp: "Es la garantía mínima frente a acreedores y determina el porcentaje de propiedad de cada socio en la empresa." },
    { u: "ADIPLE T1", q: "Una 'Sociedad Cooperativa' busca primordialmente:", opts: ["Hacerse rico a costa de otros.", "Satisfacer las necesidades de sus socios y crear empleo estable.", "No pagar impuestos.", "Ser una empresa de una sola persona."], ans: 1, exp: "Se basan en la ayuda mutua y la solidaridad entre socios, quienes suelen ser a la vez trabajadores o proveedores." },
    { u: "ADIPLE T1", q: "¿Qué es el I.V.A.?", opts: ["Impuesto sobre las Ventas Automáticas.", "Impuesto sobre el Valor Añadido (impuesto indirecto al consumo).", "Inversión de Valor Anual.", "Impuesto sobre Vehículos de Alquiler."], ans: 1, exp: "Es el impuesto que recae sobre el consumidor final cada vez que adquiere un producto o servicio." },
    { u: "ADIPLE T1", q: "El 'Balance de Situación' muestra:", opts: ["La lista de precios.", "La imagen fiel del patrimonio de la empresa en un momento dado.", "La temperatura de la oficina.", "El currículum del gerente."], ans: 1, exp: "Es una 'fotografía' financiera que divide lo que se tiene (Activo) de lo que se debe (Pasivo y Patrimonio Neto)." },
    { u: "ADIPLE T1", q: "La 'Cuenta de Pérdidas y Ganancias' detalla:", opts: ["El nombre de los clientes.", "El resultado económico del ejercicio (Ingresos menos Gastos).", "La dirección de la empresa.", "El color del logotipo."], ans: 1, exp: "Indica si la actividad de la empresa durante el año ha generado beneficios o ha incurrido en pérdidas." },
    { u: "ADIPLE T1", q: "¿Qué es el 'Umbral de Rentabilidad' o Punto Muerto?", opts: ["El momento en que muere el empresario.", "El volumen de ventas necesario para cubrir todos los gastos (beneficio cero).", "El precio máximo de un producto.", "La fecha de cierre de la fábrica."], ans: 1, exp: "A partir de este número de ventas, la empresa empieza a ganar dinero realmente." },
    { u: "ADIPLE T1", q: "Los 'Recursos Humanos' de una empresa son:", opts: ["Las máquinas de café.", "El conjunto de personas que trabajan en la organización.", "Las mesas y sillas.", "Los folletos publicitarios."], ans: 1, exp: "Se considera el activo más valioso de la empresa: el talento, esfuerzo y conocimiento de su personal." },
    { u: "ADIPLE T1", q: "El 'Marketing' se encarga de:", opts: ["Arreglar las máquinas rotas.", "Identificar y satisfacer las necesidades de los clientes de forma rentable.", "Solo de poner anuncios en la tele.", "Limpiar el almacén."], ans: 1, exp: "Engloba desde el diseño del producto y el precio hasta la distribución y la comunicación con el público." },
    { u: "ADIPLE T1", q: "¿Qué es una 'Acción' en una S.A.?", opts: ["Un movimiento de gimnasia.", "Parte proporcional del capital social que otorga derechos al socio.", "Un préstamo del banco.", "Una multa de tráfico."], ans: 1, exp: "Ser dueño de acciones te convierte en copropietario de la empresa, dándote derecho a participar en los beneficios (dividendos)." },
    { u: "ADIPLE T1", q: "Un 'Acreedor' es:", opts: ["Alguien que nos debe dinero.", "Alguien a quien nosotros debemos dinero.", "El dueño de la empresa.", "Un cliente fiel."], ans: 1, exp: "Son personas o bancos que han entregado bienes o dinero a la empresa y esperan el pago." },
    { u: "ADIPLE T1", q: "El 'I.R.P.F.' es un impuesto que grava:", opts: ["Las ventas de productos.", "La renta de las personas físicas (salarios, ahorros).", "La propiedad de las casas.", "La gasolina."], ans: 1, exp: "Es un impuesto progresivo: paga un mayor porcentaje quien tiene unos ingresos más altos." },
    { u: "ADIPLE T1", q: "La 'Liquidez' de una empresa es:", opts: ["La cantidad de agua en el depósito.", "Su capacidad para afrontar pagos inmediatos en efectivo.", "Lo rápido que se mueve la maquinaria.", "El peso de los productos líquidos."], ans: 1, exp: "Tener beneficios no es lo mismo que tener liquidez; una empresa puede quebrar si no tiene efectivo para pagar la nómina hoy." },
    { u: "ADIPLE T1", q: "¿Qué significa 'Solvencia'?", opts: ["Que la empresa tiene mucho aire.", "Capacidad de la empresa para pagar sus deudas a largo plazo con sus activos.", "Que los trabajadores son amables.", "Que la empresa es muy conocida."], ans: 1, exp: "La solvencia mide el respaldo total de los bienes de la empresa frente a todas sus deudas acumuladas." },
    { u: "ADIPLE T1", q: "El 'Factoring' es un servicio financiero que consiste en:", opts: ["Fabricar piezas.", "Adelantar el cobro de las facturas de los clientes a cambio de una comisión.", "Comprar ordenadores.", "Vender coches usados."], ans: 1, exp: "Permite a la empresa obtener dinero rápido vendiendo sus recibos de clientes a un banco." },
    { u: "ADIPLE T1", q: "Un 'Leasing' es:", opts: ["Un regalo.", "Un contrato de alquiler con opción a compra.", "Un seguro de vida.", "Un tipo de motor."], ans: 1, exp: "Muy usado para furgonetas o maquinaria; pagas una cuota mensual y al final puedes quedártelo pagando un poco más." },
    { u: "ADIPLE T1", q: "El 'Dividendo' es:", opts: ["Una operación matemática de primaria.", "La parte del beneficio de la empresa que se reparte entre los accionistas.", "El precio de la luz.", "Una marca de calculadoras."], ans: 1, exp: "Es la 'propina' anual que reciben los dueños por haber invertido su capital en la sociedad." },
    { u: "ADIPLE T1", q: "¿Qué es el 'E.B.I.T.D.A.'?", opts: ["Un código de seguridad secreto.", "Beneficio antes de intereses, impuestos, depreciaciones y amortizaciones.", "El nombre del presidente de la empresa.", "Un impuesto de la Unión Europea."], ans: 1, exp: "Muestra el beneficio puramente operativo de la empresa, sin contar rollos de bancos ni de hacienda." },
    { u: "ADIPLE T1", q: "La 'Responsabilidad Social Corporativa' (RSC) implica:", opts: ["Pagar solo los salarios mínimos.", "Compromiso voluntario de la empresa con la mejora social, económica y ambiental.", "Cumplir la ley únicamente.", "Hacer fiestas para los socios."], ans: 1, exp: "La empresa decide ser 'buena ciudadana', ayudando al barrio, reciclando o fomentando la igualdad." },
    { u: "ADIPLE T1", q: "Un 'Monopolio' ocurre cuando:", opts: ["Hay muchos vendedores compitiendo.", "Existe un único vendedor de un producto en el mercado.", "Nadie quiere comprar nada.", "El Estado regala el dinero."], ans: 1, exp: "Al no tener competencia, el monopolista puede fijar precios más altos y perjudicar al consumidor." },
    { u: "ADIPLE T1", q: "¿Qué es el 'P.I.B.'?", opts: ["Programa de Inversión Básica.", "Producto Interior Bruto (valor de todo lo producido en un país en un año).", "Pequeña Industria de Barrio.", "Precio de Importación de Bienes."], ans: 1, exp: "Es el termómetro de la salud económica de un país; si el PIB sube, el país está creciendo." },
    { u: "ADIPLE T1", q: "El 'Salario Mínimo Interprofesional' (SMI) lo fija:", opts: ["Cada empresa libremente.", "El Gobierno.", "Los trabajadores por sorteo.", "El banco."], ans: 1, exp: "Es la cuantía retributiva mínima que debe percibir el trabajador por su jornada legal de trabajo." },
    { u: "ADIPLE T1", q: "Una 'Patente' sirve para:", opts: ["Pintar la fachada.", "Proteger legalmente una invención industrial durante un tiempo.", "Identificar a los trabajadores.", "Para poder circular con el coche."], ans: 1, exp: "Otorga al inventor el monopolio de fabricación de su invento durante 20 años a cambio de hacerlo público." },
    { u: "ADIPLE T1", q: "El 'Benchmarking' consiste en:", opts: ["Hacer trampas en el mercado.", "Comparar los procesos y productos de nuestra empresa con los mejores del sector.", "Descansar en un banco del parque.", "Echar a los trabajadores."], ans: 1, exp: "Es aprender de los mejores para intentar igualarlos o superarlos en eficiencia." },
    { u: "ADIPLE T1", q: "Un 'Pulsador de Emergencia' económico en una empresa es:", opts: ["Un botón rojo físico.", "Un fondo de reserva para contingencias imprevistas.", "Llamar a la policía.", "Desenchufar los ordenadores."], ans: 1, exp: "Toda administración responsable guarda un remanente para poder sobrevivir si las ventas caen de golpe." },
    { u: "ADIPLE T1", q: "La 'Segmentación de Mercado' es:", opts: ["Cortar el mercado con tijeras.", "Dividir a los clientes en grupos con características similares.", "Vender a todo el mundo por igual.", "Cerrar las tiendas pequeñas."], ans: 1, exp: "Permite dirigir la publicidad solo a quien realmente puede estar interesado (ej. ropa de bebé para padres)." },
    { u: "ADIPLE T1", q: "¿Qué es el 'Just in Time'?", opts: ["Llegar tarde al trabajo.", "Sistema de producción que busca tener el material justo en el momento necesario (sin stock).", "Una marca de relojes.", "Trabajar solo por la noche."], ans: 1, exp: "Ahorra mucho dinero en almacenes, pero es arriesgado si el camión del proveedor pincha una rueda." },
    { u: "ADIPLE T1", q: "El 'Euríbor' es:", opts: ["Una moneda de chocolate.", "El tipo de interés al que se prestan dinero los bancos entre sí en Europa.", "Un impuesto de los coches.", "El nombre del banco central."], ans: 1, exp: "Es la referencia que usan la mayoría de hipotecas en España para subir o bajar la cuota cada año." },
    { u: "ADIPLE T1", q: "Una 'Subvención' es:", opts: ["Un préstamo a devolver mañana.", "Ayuda económica del sector público que no hay que devolver.", "Una multa del ayuntamiento.", "Una donación a un partido político."], ans: 1, exp: "El Estado las da para fomentar el empleo, la investigación o la energía solar." },
    { u: "ADIPLE T1", q: "El 'Networking' profesional busca:", opts: ["Jugar a videojuegos en red.", "Crear una red de contactos para generar oportunidades de negocio.", "Limpiar los cables de internet.", "Espiar a la competencia."], ans: 1, exp: "Ir a ferias y conocer a gente del sector ayuda a encontrar mejores proveedores o clientes." },
    { u: "ADIPLE T1", q: "¿Qué es el 'Capital Humano'?", opts: ["El dinero que tienen las personas.", "Los conocimientos, habilidades y salud de los trabajadores.", "Los robots con forma humana.", "El precio de una vida."], ans: 1, exp: "Cuanto más formado esté el personal, más productiva y valiosa será la empresa." },
    { u: "ADIPLE T1", q: "La 'Productividad' mide:", opts: ["Lo mucho que brilla el producto.", "La relación entre la cantidad producida y los recursos empleados.", "El peso total de la fabricación.", "Las horas que el jefe está en la oficina."], ans: 1, exp: "Ser productivo es fabricar más piezas con el mismo número de horas y de máquinas." },
    { u: "ADIPLE T1", q: "Un 'Pasivo Corriente' son deudas a:", opts: ["A pagar en más de 50 años.", "Corto plazo (menos de un año).", "Pagar nunca.", "Solo deudas con la familia."], ans: 1, exp: "Son deudas urgentes: facturas de luz, proveedores de materiales o la letra del préstamo de este mes." },
    { u: "ADIPLE T1", q: "El 'Patrimonio Neto' es:", opts: ["El dinero en el banco únicamente.", "La diferencia entre Activos y Pasivos (la riqueza real propia).", "La suma de todas las ventas.", "El sueldo del director."], ans: 1, exp: "Es lo que quedaría para los socios si la empresa vendiera todo y pagara todas sus deudas hoy." },
    { u: "ADIPLE T1", q: "La 'Globalización' económica implica:", opts: ["Vender solo en el barrio.", "Creciente integración de las economías nacionales en un mercado mundial.", "Que la tierra es redonda.", "Usar solo el dólar."], ans: 1, exp: "Permite comprar piezas en China, programarlas en España y venderlas en Alemania con facilidad." },
    { u: "ADIPLE T1", q: "Un 'Business Plan' es:", opts: ["Un mapa para ir de vacaciones.", "Documento que describe un negocio, sus objetivos y cómo alcanzarlos.", "El menú de la cena de empresa.", "Un juego de mesa financiero."], ans: 1, exp: "Es la hoja de ruta que todo emprendedor debe escribir antes de pedir dinero al banco." },
    { u: "ADIPLE T1", q: "El 'Outsourcing' consiste en:", opts: ["Contratar a familiares.", "Subcontratar servicios externos para tareas que no son el núcleo del negocio (ej. limpieza).", "Vender productos fuera del país.", "Comprar ordenadores potentes."], ans: 1, exp: "Permite a la empresa centrarse en lo que sabe hacer bien y dejar el resto a especialistas." },
    { u: "ADIPLE T1", q: "¿Qué es el 'Fondo de Maniobra'?", opts: ["Un truco de magia.", "Recursos permanentes que financian el activo corriente (colchón de seguridad).", "El volante de la furgoneta.", "El dinero para las vacaciones."], ans: 1, exp: "Un fondo de maniobra positivo indica que la empresa puede pagar sus facturas a corto plazo sin agobiarse." },
    { u: "ADIPLE T1", q: "La 'Vantaja Competitiva' es:", opts: ["Hacer trampas legales.", "Característica que diferencia a una empresa de sus rivales y le da superioridad.", "Tener el local más grande.", "Estar cerca de un banco."], ans: 1, exp: "Puede ser una tecnología secreta, una marca muy famosa o tener los costes más bajos del mundo." },
    { u: "ADIPLE T1", q: "El 'I.A.E.' es el:", opts: ["Impuesto de Actividades Económicas.", "Índice de Ahorro Externo.", "Inversión de Activos Especiales.", "Impuesto de Alquiler de Edificios."], ans: 0, exp: "Es un impuesto que grava el mero ejercicio de una actividad empresarial o profesional." },
    { u: "ADIPLE T1", q: "¿Qué es la 'Deflación'?", opts: ["Cuando los globos explotan.", "Bajada generalizada y prolongada de los precios.", "Cuando el dinero no sirve para nada.", "Un tipo de moneda digital."], ans: 1, exp: "Aunque parezca bueno, la deflación es peligrosa porque la gente deja de comprar esperando a que baje más el precio, y la economía se para." },
    { u: "ADIPLE T1", q: "Un 'Gasto' se diferencia de una 'Inversión' en que:", opts: ["No hay diferencia.", "El gasto se consume en el ejercicio; la inversión permanece varios años.", "El gasto es siempre más caro.", "La inversión es obligatoria por ley."], ans: 1, exp: "Pagar el recibo de la luz es un gasto. Comprar una fresadora CNC es una inversión (un activo)." },
    { u: "ADIPLE T1", q: "La 'Obsolescencia Programada' es:", opts: ["Cuando algo se rompe por accidente.", "Diseño de productos para que duren poco y obligar al cliente a comprar otro.", "Programar el autómata de la fábrica.", "Poner fecha a las reuniones."], ans: 1, exp: "Es una técnica criticada que busca aumentar el consumo fabricando cosas 'de usar y tirar'." },
    { u: "ADIPLE T1", q: "Un 'Paraíso Fiscal' es un país con:", opts: ["Muchos árboles y playas.", "Impuestos muy bajos o nulos para atraer capitales extranjeros.", "Solo bancos públicos.", "Sin moneda propia."], ans: 1, exp: "A menudo se usan para ocultar dinero o pagar menos de lo que corresponde en el país de origen." },
    { u: "ADIPLE T1", q: "El 'Interés Nominal' en un préstamo es:", opts: ["Lo mismo que la TAE.", "El porcentaje de interés que se acuerda pagar por el dinero prestado, sin incluir otros gastos.", "El nombre del director del banco.", "El precio de la escritura pública."], ans: 1, exp: "Es el tipo de interés 'puro'; para saber cuánto vas a pagar de verdad hay que mirar siempre la TAE." },
    { u: "ADIPLE T1", q: "La amortización de un préstamo es:", opts: ["La firma del contrato.", "El proceso de devolución del capital prestado más los intereses en el tiempo.", "El regalo que hace el banco al abrir la cuenta.", "La denuncia por falta de pago."], ans: 1, exp: "Cada cuota mensual sirve para pagar un poco de la deuda y un poco de los intereses acumulados." },
    { u: "ADIPLE T1", q: "Una 'Sociedad Mixta' según la titularidad del capital tiene:", opts: ["Socios hombres y mujeres al 50%.", "Participación tanto del Estado como de particulares.", "Negocios de agricultura e industria a la vez.", "Capital en euros y en dólares."], ans: 1, exp: "Empresas como AENA son mixtas: el gobierno tiene una parte y los inversores privados otra." },
    { u: "ADIPLE T1", q: "¿Qué sector de actividad incluye a la hostelería y al transporte?", opts: ["Primario.", "Secundario.", "Terciario.", "Industrial."], ans: 2, exp: "El sector terciario o de servicios es el que no fabrica cosas físicas, sino que ofrece atención y facilidades (comercio, turismo, banca)." },
    { u: "ADIPLE T1", q: "En una cooperativa, el principio de gestión es:", opts: ["Manda el que más dinero pone.", "Gestión democrática (un socio, un voto).", "Manda el más joven.", "Decide el Estado."], ans: 1, exp: "Este modelo garantiza que las decisiones se tomen buscando el beneficio de la mayoría y no solo de los ricos." },
    { u: "ADIPLE T1", q: "El objetivo final de la administración económica básica es:", opts: ["Ser millonario mañana.", "Lograr una gestión eficiente de los recursos y asegurar la viabilidad financiera de la actividad industrial.", "Gastar todo el presupuesto anual.", "No tener ningún tipo de deuda nunca."], ans: 1, exp: "La gestión profesional busca que la empresa sea duradera, rentable y capaz de pagar sus facturas y salarios siempre." },
// --- PREGUNTAS DE LA PLATAFORMA (MOODLE) ---
    { u: "ADIPLE T2", q: "¿Cómo se crea valor en un producto?", opts: ["Incrementando la cuota de mercado.", "Mediante una buena cadena de proveedores en el aprovisionamiento.", "Utilizando nuevas tecnologías y personal de élite.", "Añadiéndole utilidad para que satisfaga necesidades."], ans: 3, exp: "La creación de valor consiste en transformar inputs en un producto final que resulte más útil para el cliente de lo que eran sus componentes por separado, permitiendo cobrar un precio superior al coste de producción." },
    { u: "ADIPLE T2", q: "¿Qué tipo de tributo es aquel que no conlleva contraprestación directa y que se dedica a la financiación general del gasto público?", opts: ["Impuestos.", "Contribuciones especiales.", "Tasas.", "Sablazos."], ans: 0, exp: "Los impuestos son tributos exigidos sin una contraprestación específica individualizada, cuyo fin es sostener los gastos comunes del Estado (sanidad, educación, defensa, etc.)." },
    { u: "ADIPLE T2", q: "Cuando el vendedor quiere dejar constancia de la oferta de un determinado bien o servicio y sus condiciones de entrega, utilizará:", opts: ["La factura.", "El presupuesto.", "El albarán.", "El pedido."], ans: 1, exp: "El presupuesto es el documento informativo inicial donde se detallan los precios, calidades y plazos para que el cliente decida si acepta o no la operación comercial." },
    { u: "ADIPLE T2", q: "El documento formal que incorpora una orden de pago, mediante el cual una persona ordena a una entidad bancaria que pague una determinada cantidad de dinero a otra persona, es:", opts: ["Recibo.", "Transferencia bancaria.", "Cheque.", "Letra de cambio."], ans: 2, exp: "El cheque es un título valor de pago inmediato que permite al tenedor retirar los fondos indicados de la cuenta del emisor en la entidad bancaria correspondiente." },
    { u: "ADIPLE T2", q: "El documento que acredita la entrega de la mercancía por parte del vendedor al comprador, y que debe ser firmado por este último, se llama:", opts: ["Factura.", "Albarán.", "Pedido.", "Presupuesto."], ans: 1, exp: "El albarán (o nota de entrega) sirve como prueba legal de que la mercancía ha cambiado de manos y que el comprador está conforme con lo recibido en ese momento." },
    { u: "ADIPLE T2", q: "El Impuesto sobre Sociedades (IS) grava:", opts: ["La renta de las personas físicas.", "El beneficio obtenido por las personas jurídicas (empresas).", "El valor añadido en cada etapa de producción.", "La propiedad de vehículos de tracción mecánica."], ans: 1, exp: "El IS es un impuesto directo y personal que recae sobre la riqueza neta (beneficios) obtenida por las sociedades mercantiles y otras entidades jurídicas." },
    { u: "ADIPLE T2", q: "El marketing-mix se compone de las variables conocidas como las 4 Pes. ¿Cuáles son?", opts: ["Precio, Producto, Publicidad y Personas.", "Precio, Producto, Promoción y Plaza (Distribución).", "Paciencia, Prudencia, Pericia y Pasión.", "Planificación, Producción, Posicionamiento y Precio."], ans: 1, exp: "Las 4 Pes (Product, Price, Place, Promotion) representan las herramientas tácticas que la empresa combina para obtener la respuesta deseada en el mercado objetivo." },
    { u: "ADIPLE T2", q: "La segmentación de mercados consiste en:", opts: ["Dividir el mercado en grupos de compradores con características y necesidades similares.", "Vender el mismo producto a todas las personas del mundo por igual.", "Fabricar el producto en partes o segmentos diferentes.", "Eliminar a la competencia de un sector determinado."], ans: 0, exp: "Segmentar permite a la empresa adaptar su oferta y comunicación a las particularidades de cada grupo, aumentando la efectividad de sus campañas de marketing." },
    { u: "ADIPLE T2", q: "Las siglas DAFO representan una herramienta de análisis estratégico. ¿Qué significan?", opts: ["Dinero, Ahorro, Finanzas y Operaciones.", "Debilidades, Amenazas, Fortalezas y Oportunidades.", "Dirección, Administración, Facturación y Organización.", "Desarrollo, Aptitud, Formación y Objetivos."], ans: 1, exp: "El análisis DAFO combina el estudio interno (Fortalezas y Debilidades) con el externo (Oportunidades y Amenazas) para definir la estrategia competitiva de la empresa." },
    { u: "ADIPLE T2", q: "Un mercado en el que existe un solo vendedor y muchos compradores se denomina:", opts: ["Competencia perfecta.", "Oligopolio.", "Monopolio.", "Competencia monopolística."], ans: 2, exp: "En el monopolio, la falta de competencia permite a la empresa única tener un control casi total sobre los precios y las cantidades de producto ofrecidas." },

    // --- BLOQUE CUESTIONARIO DE AUTOEVALUACIÓN (70 PREGUNTAS) ---
    { u: "ADIPLE T2", q: "¿Cuál es la primera etapa del proceso de planificación estratégica?", opts: ["Ejecución de las tareas.", "Análisis de la situación actual (interno y externo).", "Despido de personal.", "Compra de maquinaria nueva."], ans: 1, exp: "Antes de fijar objetivos o actuar, es imprescindible conocer dónde está la empresa y qué ocurre en su entorno." },
    { u: "ADIPLE T2", q: "La 'Misión' de una empresa define:", opts: ["Lo que la empresa quiere ser en el futuro lejano.", "La razón de ser de la empresa y su actividad básica en el presente.", "El precio de sus productos.", "La dirección de su oficina principal."], ans: 1, exp: "La misión responde a la pregunta '¿A qué nos dedicamos?' y sirve de guía para el comportamiento diario de la organización." },
    { u: "ADIPLE T2", q: "La 'Visión' empresarial se refiere a:", opts: ["La capacidad visual de los empleados.", "La imagen de futuro que la empresa quiere alcanzar a largo plazo.", "La lista de facturas pendientes.", "La marca del logotipo."], ans: 1, exp: "La visión es una declaración aspiracional que motiva a la organización a alcanzar una meta ambiciosa en los próximos 10 o 20 años." },
    { u: "ADIPLE T2", q: "En el análisis DAFO, las 'Amenazas' son:", opts: ["Factores internos positivos.", "Factores externos negativos que pueden perjudicar a la empresa.", "Habilidades especiales de los trabajadores.", "Problemas de luz en la oficina."], ans: 1, exp: "Son situaciones del entorno (como nuevas leyes o crisis económica) sobre las que la empresa no tiene control directo pero que debe prever." },
    { u: "ADIPLE T2", q: "En el análisis DAFO, las 'Fortalezas' son:", opts: ["Debilidades del mercado.", "Capacidades y recursos internos positivos de la propia empresa.", "Subvenciones del gobierno.", "La fuerza física de los operarios."], ans: 1, exp: "Son las ventajas competitivas propias, como una tecnología única, una marca fuerte o un personal muy formado." },
    { u: "ADIPLE T2", q: "El modelo de las '5 Fuerzas de Porter' sirve para analizar:", opts: ["El clima meteorológico.", "El atractivo y la intensidad competitiva de un sector industrial.", "La resistencia de los materiales.", "La potencia de los motores."], ans: 1, exp: "Analiza el poder de clientes, proveedores, nuevos competidores, productos sustitutos y la rivalidad interna para determinar si el sector es rentable." },
    { u: "ADIPLE T2", q: "¿Qué analiza el factor 'P' del análisis PESTEL?", opts: ["La presión atmosférica.", "Los factores Políticos (estabilidad gubernamental, tratados, etc.).", "El precio de los productos.", "El personal de la empresa."], ans: 1, exp: "PESTEL analiza el macroentorno; la P se centra en cómo la política nacional o internacional afecta al negocio." },
    { u: "ADIPLE T2", q: "El 'Marketing Estratégico' se encarga de:", opts: ["Poner anuncios en redes sociales.", "Detectar necesidades y definir el mercado objetivo a largo plazo.", "Limpiar el escaparate.", "Hacer llamadas de venta directa."], ans: 1, exp: "Es la parte reflexiva del marketing: analiza el mercado para decidir qué productos lanzar y a quién dirigirse antes de empezar a vender." },
    { u: "ADIPLE T2", q: "El 'Marketing Operativo' consiste en:", opts: ["Pensar en el futuro de la empresa.", "Ejecutar las acciones tácticas (las 4 Pes) para alcanzar los objetivos.", "Contratar ingenieros.", "Pagar a los proveedores."], ans: 1, exp: "Es el marketing de acción: poner el precio, diseñar el envase, gestionar la tienda y hacer la publicidad." },
    { u: "ADIPLE T2", q: "Un producto 'Perro' en la matriz BCG es aquel que:", opts: ["Es el mejor amigo del hombre.", "Tiene baja cuota de mercado y bajo crecimiento (poco rentable).", "Es el más vendido de la empresa.", "Es una novedad tecnológica."], ans: 1, exp: "Son productos que suelen consumir recursos y no generan beneficios significativos, recomendándose a menudo su eliminación." },
    { u: "ADIPLE T2", q: "Un producto 'Estrella' en la matriz BCG se caracteriza por:", opts: ["No venderse nada.", "Alta cuota de mercado en un mercado de rápido crecimiento.", "Estar pasado de moda.", "Ser muy barato de fabricar."], ans: 1, exp: "Generan ventas altas pero requieren mucha inversión para mantener su liderazgo frente a la competencia." },
    { u: "ADIPLE T2", q: "¿Qué es el 'Posicionamiento' de marca?", opts: ["El lugar físico donde se pone el cartel.", "El lugar que ocupa la marca en la mente del consumidor respecto a la competencia.", "La dirección GPS de la fábrica.", "El orden en la lista de proveedores."], ans: 1, exp: "Es la imagen que proyectamos (calidad, lujo, ahorro) para que el cliente nos identifique rápidamente." },
    { u: "ADIPLE T2", q: "El 'Ciclo de Vida' de un producto consta de las fases:", opts: ["Compra, Uso y Tirado.", "Introducción, Crecimiento, Madurez y Declive.", "Enero, Febrero, Marzo y Abril.", "Metal, Plástico y Cristal."], ans: 1, exp: "Representa la evolución de las ventas y beneficios desde que el producto nace hasta que desaparece del mercado." },
    { u: "ADIPLE T2", q: "¿Qué ocurre en la fase de 'Madurez' de un producto?", opts: ["Las ventas caen a cero.", "Las ventas se estabilizan y la competencia es máxima.", "Nadie conoce el producto.", "El precio es el más alto posible."], ans: 1, exp: "Es la fase más larga y rentable, donde el producto ya es conocido y la empresa lucha por mantener su cuota de mercado." },
    { u: "ADIPLE T2", q: "La variable 'Plaza' en el marketing-mix se refiere a:", opts: ["Un jardín público.", "Los canales de distribución y puntos de venta.", "El tamaño de la fábrica.", "El aparcamiento de los camiones."], ans: 1, exp: "Define cómo llega el producto desde el fabricante hasta el consumidor final (tiendas físicas, online, mayoristas)." },
    { u: "ADIPLE T2", q: "La 'Promoción' (Comunicación) en marketing incluye:", opts: ["Solo bajar los precios.", "Publicidad, relaciones públicas, venta personal y promoción de ventas.", "Solo el nombre de la empresa.", "La limpieza de los camiones."], ans: 1, exp: "Engloba todas las formas de dar a conocer el producto y persuadir al cliente para que lo compre." },
    { u: "ADIPLE T2", q: "¿Qué es la 'Cadena de Valor' de Porter?", opts: ["Una joya de oro.", "Herramienta que desglosa las actividades de la empresa para identificar fuentes de ventaja competitiva.", "Una lista de precios de proveedores.", "Un sistema de seguridad."], ans: 1, exp: "Analiza cada paso (logística, producción, ventas) para ver dónde se puede aportar más utilidad al cliente al menor coste." },
    { u: "ADIPLE T2", q: "La 'Contabilidad de Costes' sirve para:", opts: ["Pagar a Hacienda.", "Calcular cuánto cuesta fabricar cada producto y fijar precios de forma rentable.", "Saber el nombre de los socios.", "Medir la temperatura de la nave."], ans: 1, exp: "Permite una gestión interna eficiente al identificar qué productos son rentables y cuáles no." },
    { u: "ADIPLE T2", q: "¿Qué es el 'Punto de Pedido'?", opts: ["La dirección de la tienda.", "El nivel de existencias en el que se debe realizar un nuevo pedido para no quedarse sin stock.", "La fecha del calendario.", "El nombre del repartidor."], ans: 1, exp: "Calculado correctamente, evita la rotura de stock y asegura que el material llegue antes de que se agote el actual." },
    { u: "ADIPLE T2", q: "El 'Just in Time' (JIT) busca principalmente:", opts: ["Llegar tarde.", "Minimizar los niveles de inventario y los costes de almacenamiento.", "Comprar todo el material del año en enero.", "No tener proveedores."], ans: 1, exp: "Es una filosofía de gestión donde el material llega justo cuando se necesita para entrar en producción." },
    { u: "ADIPLE T2", q: "¿Qué es una 'Factura Rectificativa'?", opts: ["Un regalo.", "Documento que corrige errores o devoluciones de una factura anterior.", "Una factura de color rojo.", "Un documento ilegal."], ans: 1, exp: "Se utiliza obligatoriamente para modificar el importe o los datos de una factura que ya ha sido emitida." },
    { u: "ADIPLE T2", q: "El 'Recibo' de pago es un documento que:", opts: ["Emite el comprador.", "Emite el vendedor para certificar que ha cobrado una cantidad determinada.", "Sirve para pedir un préstamo.", "Es igual que el presupuesto."], ans: 1, exp: "A diferencia de la factura (que indica deuda), el recibo es el comprobante final de que el dinero ha sido entregado." },
    { u: "ADIPLE T2", q: "La 'Letra de Cambio' es un documento que incorpora:", opts: ["Una orden incondicional de pago a una fecha de vencimiento determinada.", "Una foto de la empresa.", "La lista de trabajadores.", "El manual del motor."], ans: 0, exp: "Es un título valor muy utilizado en el comercio entre empresas para aplazar el pago de las operaciones." },
    { u: "ADIPLE T2", q: "¿Qué es el 'Endoso' de un cheque o letra?", opts: ["Romperlo.", "Transmitir el derecho de cobro a otra persona mediante la firma al dorso.", "Pintarlo de azul.", "Llevarlo al banco."], ans: 1, exp: "Permite usar un documento de cobro futuro como si fuera dinero para pagar a un tercero." },
    { u: "ADIPLE T2", q: "La 'Conciliación Bancaria' consiste en:", opts: ["Hacerse amigo del banquero.", "Comprobar que los movimientos del banco coinciden con los libros contables de la empresa.", "Pedir un descuento.", "Abrir una cuenta nueva."], ans: 1, exp: "Es una tarea administrativa vital para detectar errores, comisiones no previstas o pagos no registrados." },
    { u: "ADIPLE T2", q: "¿Qué es el I.A.E.?", opts: ["Impuesto de Actividades Económicas (grava el ejercicio de una actividad profesional).", "Inversión de Activos Externos.", "Impuesto al Aire Especial.", "Información de Acciones Españolas."], ans: 0, exp: "Es un tributo municipal obligatorio para cualquier empresa o profesional que realice una actividad económica en España." },
    { u: "ADIPLE T2", q: "El 'Hecho Imponible' de un impuesto es:", opts: ["La fecha de pago.", "La circunstancia o acción que genera la obligación legal de pagar el impuesto.", "El nombre del funcionario.", "La multa por no pagar."], ans: 1, exp: "En el IVA, el hecho imponible es la venta del producto; en el IRPF, es la obtención de una renta o salario." },
    { u: "ADIPLE T2", q: "¿Qué significa que un impuesto sea 'Progresivo'?", opts: ["Que se paga poco a poco.", "Que el porcentaje a pagar aumenta según aumenta la riqueza del contribuyente.", "Que siempre es el mismo para todos.", "Que se paga solo en el futuro."], ans: 1, exp: "El IRPF es el ejemplo clásico: quien gana 100.000 euros paga un tipo (porcentaje) superior al que gana 20.000." },
    { u: "ADIPLE T2", q: "La 'Base Imponible' de una factura es:", opts: ["El total a pagar con impuestos.", "El importe neto de los bienes o servicios antes de aplicar los impuestos.", "El número de la factura.", "El nombre del cliente."], ans: 1, exp: "Es la cantidad sobre la que se calcula el porcentaje de IVA o retención correspondiente." },
    { u: "ADIPLE T2", q: "¿Qué es un 'Arrendamiento Financiero' (Leasing)?", opts: ["Un préstamo personal.", "Alquiler con opción a compra de un bien (vehículo, máquina) al final del contrato.", "Un regalo de la empresa.", "Un seguro de vida."], ans: 1, exp: "Es una forma de financiar activos sin desembolsar todo el capital de golpe, permitiendo beneficios fiscales." },
    { u: "ADIPLE T2", q: "La 'Tesorería' de una empresa se encarga de:", opts: ["Fabricar los productos.", "Gestionar el flujo de caja (cobros y pagos) y asegurar que haya dinero disponible.", "Contratar empleados.", "Limpiar las oficinas."], ans: 1, exp: "Vigila que la empresa sea capaz de pagar sus facturas y nóminas hoy mismo, evitando la quiebra por falta de liquidez." },
    { u: "ADIPLE T2", q: "¿Qué es el 'Factoring'?", opts: ["Fabricar piezas.", "Ceder las facturas de clientes a un banco para cobrarlas por adelantado a cambio de una comisión.", "Comprar una fábrica.", "Vender acciones."], ans: 1, exp: "Es una herramienta financiera para obtener dinero rápido sin esperar a que el cliente pague a 60 o 90 días." },
    { u: "ADIPLE T2", q: "La sigla 'Pyme' significa:", opts: ["Pequeña y Muy Eficiente.", "Pequeña y Mediana Empresa.", "Producción y Marketing Externo.", "Punto de Venta Mecanizado."], ans: 1, exp: "Constituyen la inmensa mayoría del tejido empresarial, teniendo límites de facturación y número de empleados." },
    { u: "ADIPLE T2", q: "Un 'Acreedor' se diferencia de un 'Proveedor' en que:", opts: ["No hay diferencia.", "El proveedor suministra mercancías del negocio; el acreedor presta servicios o dinero ajenos al producto.", "El acreedor es siempre el Estado.", "El proveedor es un familiar."], ans: 1, exp: "Compramos el hierro al proveedor, pero debemos la luz o el alquiler al acreedor." },
    { u: "ADIPLE T2", q: "¿Qué es el 'Capital Humano'?", opts: ["El dinero que tienen los obreros.", "El valor económico de las habilidades, formación y experiencia de los empleados.", "Un robot industrial.", "La suma de los salarios."], ans: 1, exp: "Invertir en formación mejora el capital humano y, por tanto, la productividad de la empresa." },
    { u: "ADIPLE T2", q: "El 'Outsourcing' consiste en:", opts: ["Contratar a familiares.", "Subcontratar tareas no críticas (limpieza, mantenimiento) a empresas externas especializadas.", "Vender fuera del país.", "Comprar ordenadores nuevos."], ans: 1, exp: "Permite a la empresa centrarse en su actividad principal (core business) y ganar eficiencia." },
    { u: "ADIPLE T2", q: "¿Qué analiza el factor 'E' del análisis PESTEL?", opts: ["La Energía consumida.", "Los factores Económicos (inflación, tipos de interés, desempleo, etc.).", "La Edad de los socios.", "El Estilo de los coches."], ans: 1, exp: "Analiza cómo la salud económica del país o región influye en las ventas y costes de la empresa." },
    { u: "ADIPLE T2", q: "La 'Estrategia de Liderazgo en Costes' busca:", opts: ["Ser el más caro del mercado.", "Tener los costes de producción más bajos para competir por precio.", "Vender solo por internet.", "Tener el local más grande."], ans: 1, exp: "Permite a la empresa obtener beneficios incluso si los precios del mercado bajan mucho." },
    { u: "ADIPLE T2", q: "La 'Estrategia de Diferenciación' consiste en:", opts: ["Ser igual que los demás.", "Crear un producto percibido como único por el cliente (calidad, diseño, marca).", "Bajar el precio al mínimo.", "No hacer publicidad."], ans: 1, exp: "Al ser único, el cliente está dispuesto a pagar un precio superior ('premium')." },
    { u: "ADIPLE T2", q: "Un 'Mercado de Competencia Perfecta' tiene:", opts: ["Un solo vendedor.", "Muchos compradores y vendedores con productos idénticos y total transparencia.", "Solo dos empresas.", "Precios fijados por el gobierno."], ans: 1, exp: "Es un modelo teórico donde nadie tiene poder para fijar el precio; el mercado se regula solo." },
    { u: "ADIPLE T2", q: "¿Qué es un 'Oligopolio'?", opts: ["Un mercado con muchos vendedores pequeños.", "Un mercado dominado por un número muy reducido de grandes vendedores.", "Venta de productos usados.", "Un mercado sin leyes."], ans: 1, exp: "Las decisiones de una empresa afectan mucho a las demás (ej. compañías eléctricas o de telefonía)." },
    { u: "ADIPLE T2", q: "La 'Base Liquidable' en un impuesto es:", opts: ["El dinero en el banco.", "El resultado de aplicar deducciones y reducciones a la base imponible.", "La multa por no pagar.", "El nombre del banco."], ans: 1, exp: "Es la cantidad definitiva sobre la que se aplica el tipo de gravamen (porcentaje)." },
    { u: "ADIPLE T2", q: "¿Qué es el 'Tipo de Gravamen'?", opts: ["Una enfermedad grave.", "El porcentaje que se aplica sobre la base para calcular el impuesto.", "El peso de la maquinaria.", "La fecha de vencimiento."], ans: 1, exp: "Por ejemplo, el 21% en el IVA general o el 25% en el Impuesto de Sociedades." },
    { u: "ADIPLE T2", q: "La 'Cuota Tributaria' es:", opts: ["El nombre del impuesto.", "El resultado final de aplicar el tipo a la base (la cantidad a pagar).", "El número de socio.", "El sueldo del director."], ans: 1, exp: "Es la deuda total que el contribuyente tiene con la Hacienda Pública." },
    { u: "ADIPLE T2", q: "¿Qué es el 'Sujeto Pasivo' en un impuesto?", opts: ["La persona que recibe el dinero.", "La persona física o jurídica obligada por ley al cumplimiento de las prestaciones tributarias.", "Un trabajador que no hace nada.", "El nombre de la empresa de transporte."], ans: 1, exp: "Es quien tiene que presentar la declaración y pagar el dinero a la Agencia Tributaria." },
    { u: "ADIPLE T2", q: "El 'Libro Diario' contable registra:", opts: ["Las noticias del día.", "Las operaciones económicas de la empresa día a día por orden cronológico.", "Los nombres de los clientes.", "El inventario de muebles."], ans: 1, exp: "Es obligatorio por ley y permite trazar toda la actividad financiera de la sociedad." },
    { u: "ADIPLE T2", q: "El 'Libro de Inventarios y Cuentas Anuales' incluye:", opts: ["Solo los folletos de publicidad.", "El balance, la cuenta de pérdidas y ganancias y el detalle de bienes de la empresa.", "La lista de la compra.", "Los carnets de los trabajadores."], ans: 1, exp: "Recoge la situación económica profunda de la empresa al cierre de cada ejercicio." },
    { u: "ADIPLE T2", q: "¿Qué significa que un bien sea 'Tangible'?", opts: ["Que se puede tocar físicamente.", "Que es un servicio invisible.", "Que es una idea.", "Que no tiene precio."], ans: 0, exp: "Los productos como una fresadora o un PLC son bienes tangibles; la asesoría legal es un bien intangible." },
    { u: "ADIPLE T2", q: "La 'Logística de Entrada' se ocupa de:", opts: ["Enviar los productos al cliente.", "La recepción, almacenamiento y gestión de materias primas y suministros.", "Contratar vendedores.", "Hacer el diseño del producto."], ans: 1, exp: "Es una actividad primaria de la cadena de valor fundamental para que la fábrica no se pare." },
    { u: "ADIPLE T2", q: "La 'Logística de Salida' (Distribución) gestiona:", opts: ["La compra de hierro.", "El almacenamiento y entrega de los productos terminados a los clientes.", "El pago de las nóminas.", "La limpieza de la oficina."], ans: 1, exp: "Asegura que el cliente reciba lo que compró en el tiempo y forma acordados." },
    { u: "ADIPLE T2", q: "¿Qué es un 'Canal de Distribución Directo'?", opts: ["Vender a través de 5 mayoristas.", "Venta del fabricante al consumidor final sin intermediarios.", "Vender solo en Navidad.", "Venta por catálogo de otra empresa."], ans: 1, exp: "Ejemplos son las tiendas propias del fabricante o su propia página web de e-commerce." },
    { u: "ADIPLE T2", q: "La 'Publicidad' se diferencia de las 'Relaciones Públicas' en que:", opts: ["Es más barata.", "La publicidad es un mensaje pagado y controlado; las RR.PP. buscan crear una imagen favorable.", "La publicidad es ilegal.", "No hay diferencia."], ans: 1, exp: "La publicidad busca la venta directa; las RR.PP. gestionan la reputación de la empresa ante la sociedad." },
    { u: "ADIPLE T2", q: "¿Qué es el 'Benchmarking'?", opts: ["Hacer trampas.", "Analizar y comparar las mejores prácticas de la competencia para aplicarlas a nuestra empresa.", "Sentarse en un banco.", "Despedir a los gerentes."], ans: 1, exp: "Es aprender de los líderes del sector para intentar mejorar la propia eficiencia operativa." },
    { u: "ADIPLE T2", q: "La 'Ventaja Competitiva Sostenible' es aquella que:", opts: ["Dura solo un día.", "Es difícil de imitar por la competencia y se mantiene a largo plazo.", "Es muy barata.", "Solo la conoce el dueño."], ans: 1, exp: "Tener una patente o una cultura empresarial única son fuentes de ventaja sostenible." },
    { u: "ADIPLE T2", q: "En el análisis PESTEL, el factor 'L' se refiere a:", opts: ["Limpieza.", "Factores Legales (leyes laborales, de seguridad, patentes, etc.).", "Logística.", "Liderazgo."], ans: 1, exp: "Es vital conocer el marco legal para evitar multas y aprovechar incentivos normativos." },
    { u: "ADIPLE T2", q: "Un 'Plan de Marketing' debe ser:", opts: ["Un secreto.", "Un documento escrito, detallado y con objetivos medibles y presupuesto definido.", "Solo una idea en la cabeza del jefe.", "Un video de música."], ans: 1, exp: "La formalización permite controlar si se están cumpliendo los objetivos y corregir desviaciones." },
    { u: "ADIPLE T2", q: "¿Qué es la 'Responsabilidad Social Corporativa' (RSC)?", opts: ["Pagar impuestos obligatorios.", "Compromiso voluntario de la empresa con la mejora social y ambiental más allá de la ley.", "Hacer fiestas.", "Tener muchos socios."], ans: 1, exp: "Mejora la imagen de marca y fideliza a clientes concienciados con la ética y el planeta." },
    { u: "ADIPLE T2", q: "El 'Presupuesto de Ventas' es:", opts: ["Una factura antigua.", "La previsión de ingresos por ventas para un periodo futuro.", "El dinero que se gasta en publicidad.", "La lista de precios de la competencia."], ans: 1, exp: "Es el punto de partida para planificar el resto de la actividad (compras, personal, etc.)." },
    { u: "ADIPLE T2", q: "Un 'Gastos Fijo' es aquel que:", opts: ["Depende de cuánto se fabrique.", "No varía con el volumen de producción (ej. el alquiler de la nave).", "Solo se paga una vez en la vida.", "Es de bajo importe."], ans: 1, exp: "Hay que pagarlos aunque la fábrica esté parada, por lo que suponen un riesgo financiero." },
    { u: "ADIPLE T2", q: "Un 'Gasto Variable' se caracteriza por:", opts: ["Ser siempre igual.", "Aumentar o disminuir proporcionalmente a la producción (ej. materias primas).", "Ser un secreto.", "Ser ilegal."], ans: 1, exp: "Si no fabricamos, no incurrimos en este gasto; es más seguro para la empresa." },
    { u: "ADIPLE T2", q: "El 'Margen de Contribución' es:", opts: ["Un impuesto nuevo.", "La diferencia entre el precio de venta y el coste variable unitario.", "La suma de todas las ventas.", "El sueldo del gerente."], ans: 1, exp: "Indica cuánto aporta cada unidad vendida para cubrir los costes fijos y generar beneficio." },
    { u: "ADIPLE T2", q: "¿Qué es el 'Factoring con Recurso'?", opts: ["Un regalo.", "El banco adelanta el dinero pero si el cliente no paga, la empresa debe devolverlo al banco.", "El banco asume todo el riesgo de impago.", "Vender máquinas."], ans: 1, exp: "Es más barato que el 'sin recurso' porque la empresa sigue asumiendo el riesgo final del cobro." },
    { u: "ADIPLE T2", q: "Un 'Pagaré' es:", opts: ["Una orden de pago inmediata.", "Un título valor por el que una persona se compromete a pagar a otra una cantidad en fecha fija.", "Un recibo de supermercado.", "Un tipo de moneda."], ans: 1, exp: "A diferencia del cheque, el pagaré siempre tiene una fecha de cobro futura especificada." },
    { u: "ADIPLE T2", q: "El 'IVA Soportado' es el que:", opts: ["La empresa cobra a sus clientes.", "La empresa paga a sus proveedores al comprar bienes o servicios.", "Pagan los trabajadores.", "No se puede recuperar."], ans: 1, exp: "La empresa puede deducirse este IVA en su declaración trimestral ante Hacienda." },
    { u: "ADIPLE T2", q: "El 'IVA Repercutido' es el que:", opts: ["La empresa paga por la luz.", "La empresa cobra a sus clientes en sus facturas de venta.", "Se paga una vez al año.", "Es el 0%."], ans: 1, exp: "Es dinero que la empresa recauda para luego entregárselo al Estado." },
    { u: "ADIPLE T2", q: "La 'Liquidación del IVA' consiste en:", opts: ["Gastar todo el dinero.", "Restar el IVA soportado del IVA repercutido y pagar la diferencia a Hacienda.", "Cerrar la empresa.", "Bajar los precios."], ans: 1, exp: "Si el soportado es mayor, Hacienda devuelve dinero o lo compensa para el siguiente trimestre." },
    { u: "ADIPLE T2", q: "¿Qué analiza el factor 'T' del análisis PESTEL?", opts: ["La Temperatura.", "Los factores Tecnológicos (innovación, automatización, I+D).", "El Transporte.", "La Tasa de interés."], ans: 1, exp: "Fundamental en industria para saber cuándo la tecnología propia está quedando obsoleta." },
    { u: "ADIPLE T2", q: "La 'Segmentación Geográfica' divide el mercado por:", opts: ["Edad y sexo.", "Ubicación física (países, regiones, ciudades).", "Gustos musicales.", "Nivel de estudios."], ans: 1, exp: "Es útil si el producto tiene costes de transporte altos o si el clima afecta al consumo." },
    { u: "ADIPLE T2", q: "Un 'Intermediario' en el canal de distribución es:", opts: ["Un operario de fábrica.", "Cualquier persona o empresa entre el productor y el consumidor (mayoristas, detallistas).", "El banco.", "El Estado."], ans: 1, exp: "Añaden coste al producto pero facilitan que esté disponible en muchos sitios a la vez." },
    { u: "ADIPLE T2", q: "El objetivo final de la gestión administrativa y fiscal es:", opts: ["Engañar a Hacienda.", "Cumplir la legalidad y asegurar la viabilidad económica y financiera de la empresa.", "No tener trabajadores.", "Comprar los coches más caros."], ans: 1, exp: "Una buena administración evita sanciones, optimiza los impuestos y garantiza que el negocio sea sostenible en el tiempo." },
// --- PREGUNTAS DE LA PLATAFORMA (MOODLE) ---
    { u: "ADIPLE T3", q: "¿Cuál de las siguientes no es una orientación para la actividad comercial según el enfoque del marketing?", opts: ["Orientación hacia el producto.", "Orientación hacia las ventas.", "Orientación hacia el cliente o consumidor.", "Orientación hacia la innovación tecnológica."], ans: 3, exp: "Las orientaciones clásicas son hacia la producción, el producto, las ventas y, finalmente, el marketing (cliente). La innovación tecnológica es un medio, pero no una orientación filosófica del marketing en sí misma. " },
    { u: "ADIPLE T3", q: "¿Cuál de los siguientes elementos no pertenece al concepto de mercado?", opts: ["Beneficios obtenidos por la empresa.", "Conjunto de individuos con necesidades.", "Recursos y capacidad de compra.", "Lugar de intercambio comercial."], ans: 0, exp: "El mercado se define por la demanda (personas con necesidades y dinero) y la oferta (vendedores). Los beneficios son el resultado de la actividad, pero no definen el concepto de mercado. " },
    { u: "ADIPLE T3", q: "¿Cuál es el objetivo principal del marketing relacional?", opts: ["Incrementar las ventas a corto plazo.", "Mantener una relación significativa a largo plazo con el público objetivo.", "Realizar promociones y descuentos.", "Atraer nuevos clientes a través de la publicidad masiva."], ans: 1, exp: "El marketing relacional busca fidelizar al cliente y crear un vínculo duradero que genere valor a lo largo del tiempo, más allá de una venta puntual. " },
    { u: "ADIPLE T3", q: "¿Cómo se denomina la técnica de recogida de información que consiste en la observación de un grupo de personas dirigido por un moderador?", opts: ["Encuesta.", "Entrevista en profundidad.", "Dinámica de grupo (Focus Group).", "Panel de consumidores."], ans: 2, exp: "El Focus Group es una técnica cualitativa donde un moderador guía una charla con un grupo pequeño para extraer opiniones profundas sobre un producto. " },
    { u: "ADIPLE T3", q: "¿Qué tipo de datos son aquellos que se han obtenido específicamente para el estudio que se está realizando?", opts: ["Datos secundarios.", "Datos internos.", "Datos primarios.", "Datos estadísticos."], ans: 2, exp: "Los datos primarios son información 'nueva' generada expresamente para la investigación actual, a diferencia de los secundarios que ya existían. " },
    { u: "ADIPLE T3", q: "¿Cuál es el primer paso en un proceso de investigación de mercados?", opts: ["Recogida de datos.", "Análisis de la información.", "Definición del problema y de los objetivos de la investigación.", "Presentación de resultados."], ans: 2, exp: "Antes de cualquier acción técnica, es vital saber exactamente qué queremos investigar y para qué necesitamos la información. " },
    { u: "ADIPLE T3", q: "¿Qué nombre recibe el conjunto de características que el consumidor percibe en un producto?", opts: ["Precio.", "Marca.", "Atributos del producto.", "Envase."], ans: 2, exp: "Los atributos son las cualidades físicas, estéticas o funcionales que el cliente identifica y valora al tomar su decisión de compra. " },
    { u: "ADIPLE T3", q: "¿Cuál de las siguientes es una variable de segmentación psicográfica?", opts: ["Edad.", "Nivel de ingresos.", "Estilo de vida.", "Ubicación geográfica."], ans: 2, exp: "La psicografía divide el mercado según la personalidad, los valores y las actividades cotidianas (estilo de vida) de los individuos. " },
    { u: "ADIPLE T3", q: "¿Qué herramienta se utiliza para analizar la cartera de productos de una empresa según su crecimiento y cuota de mercado?", opts: ["Análisis DAFO.", "Matriz BCG.", "Las 5 fuerzas de Porter.", "Cadena de valor."], ans: 1, exp: "La matriz de la Boston Consulting Group clasifica los productos en Estrellas, Vacas, Interrogantes y Perros. " },
    { u: "ADIPLE T3", q: "¿Cómo se define el posicionamiento de un producto?", opts: ["El lugar físico que ocupa en el estante de la tienda.", "La cuota de mercado que posee.", "La imagen que el producto proyecta en la mente del consumidor respecto a la competencia.", "El precio de venta al público."], ans: 2, exp: "Posicionarse es lograr que el cliente nos asocie con un concepto único (ej. seguridad, ahorro, lujo) frente a los rivales. " },

    // --- BLOQUE CUESTIONARIO DE AUTOEVALUACIÓN (70 PREGUNTAS) ---
    { u: "ADIPLE T3", q: "¿Qué diferencia al Marketing Industrial del Marketing de Consumo?", opts: ["El industrial vende a empresas y el de consumo a individuos finales.", "El industrial es más barato.", "El industrial solo usa radio.", "No hay ninguna diferencia."], ans: 0, exp: "En el B2B (Business to Business), las decisiones son más racionales, técnicas y suelen involucrar a varias personas del departamento de compras. " },
    { u: "ADIPLE T3", q: "La demanda de productos industriales se dice que es 'derivada' porque:", opts: ["Viene del cielo.", "Depende de la demanda de los productos de consumo final que ayudan a fabricar.", "Se calcula con derivadas matemáticas.", "Es una demanda ilegal."], ans: 1, exp: "Si la gente deja de comprar coches (consumo), las fábricas de acero dejan de vender planchas (industrial); la demanda de acero deriva del coche. " },
    { u: "ADIPLE T3", q: "Un 'Bien de Equipo' se considera:", opts: ["Materia prima.", "Producto industrial duradero necesario para el proceso productivo (maquinaria).", "Papel de oficina.", "Algo que se gasta en un día."], ans: 1, exp: "Son activos fijos como tornos, fresadoras o brazos robóticos que forman la infraestructura de la fábrica. " },
    { u: "ADIPLE T3", q: "¿Qué es el SIM (Sistema de Información de Marketing)?", opts: ["Un ordenador potente.", "Estructura de personas y procedimientos para organizar y distribuir información para la toma de decisiones.", "Un catálogo de productos.", "La red wifi de la empresa."], ans: 1, exp: "Es el engranaje que asegura que la información del mercado llegue a los directivos de forma útil y a tiempo. " },
    { u: "ADIPLE T3", q: "La investigación 'Cualitativa' busca:", opts: ["Contar el número de clientes.", "Comprender motivaciones, actitudes y comportamientos profundos.", "Hacer gráficas de barras.", "Calcular el IVA."], ans: 1, exp: "No busca números, sino el 'porqué' de las cosas, usando entrevistas o grupos de discusión. " },
    { u: "ADIPLE T3", q: "La investigación 'Cuantitativa' se caracteriza por:", opts: ["Hablar con poca gente.", "Usar muestras grandes para obtener datos estadísticamente representativos.", "No usar nunca números.", "Pintar los resultados."], ans: 1, exp: "Se basa en encuestas masivas para poder decir: 'El 80% de los clientes prefiere el color azul'. " },
    { u: "ADIPLE T3", q: "¿Qué es un 'Cuestionario'?", opts: ["Una charla informal.", "Documento con preguntas ordenadas para recoger información de forma sistemática.", "Un examen de conducir.", "Una lista de la compra."], ans: 1, exp: "Es la herramienta básica de la encuesta; permite que todos respondan lo mismo para poder comparar datos. " },
    { u: "ADIPLE T3", q: "En una encuesta, una 'Pregunta Cerrada' es aquella que:", opts: ["No se puede responder.", "Ofrece opciones de respuesta ya definidas (ej. Sí/No).", "Permite escribir un texto largo.", "Es un secreto."], ans: 1, exp: "Facilitan mucho el análisis estadístico posterior al limitar las respuestas posibles. " },
    { u: "ADIPLE T3", q: "La 'Segmentación de Mercados' sirve para:", opts: ["Vender a todo el mundo por igual.", "Identificar grupos homogéneos para adaptar la oferta comercial.", "Cortar el producto en trozos.", "Subir los precios a todos."], ans: 1, exp: "Permite ser más eficiente: no gastas publicidad en gente que no te va a comprar nunca. " },
    { u: "ADIPLE T3", q: "La segmentación por 'Criterios Geográficos' utiliza:", opts: ["La personalidad.", "Países, regiones, ciudades o clima.", "La edad y el sexo.", "El nivel de estudios."], ans: 1, exp: "Es fundamental si el producto depende de la ubicación (ej. vender máquinas de nieve en el norte). " },
    { u: "ADIPLE T3", q: "¿Qué es la 'Estrategia de Marketing Diferenciada'?", opts: ["Vender un solo producto a todo el mercado.", "Diseñar una oferta y un plan de marketing distinto para cada segmento.", "Ignorar a la competencia.", "Hacer siempre lo mismo."], ans: 1, exp: "Es más cara pero más efectiva, ya que personalizas el mensaje para cada tipo de cliente. " },
    { u: "ADIPLE T3", q: "La 'Matriz de Ansoff' se utiliza para identificar:", opts: ["El precio del producto.", "Estrategias de crecimiento (mercado/producto).", "El color del logotipo.", "A los trabajadores vagos."], ans: 1, exp: "Analiza si debemos crecer vendiendo lo mismo a gente nueva, o cosas nuevas a la misma gente. " },
    { u: "ADIPLE T3", q: "En el Marketing-Mix industrial, el 'Servicio Post-venta' es:", opts: ["Algo opcional que casi no importa.", "Un factor crítico de diferenciación y fidelización del cliente.", "Un gasto innecesario.", "Solo para coches."], ans: 1, exp: "En industria, que el proveedor te arregle la máquina rápido si se rompe es más importante a veces que el precio de compra. " },
    { u: "ADIPLE T3", q: "El 'Precio' en el marketing industrial suele ser:", opts: ["Fijo e inamovible.", "Negociado caso por caso según volumen y condiciones.", "Igual al coste de fabricación.", "Decidido por el Estado."], ans: 1, exp: "Las compras industriales son voluminosas y permiten pactar descuentos por fidelidad o cantidad. " },
    { u: "ADIPLE T3", q: "La 'Comunicación' industrial prefiere habitualmente:", opts: ["Anuncios en televisión en horario de máxima audiencia.", "Fuerza de ventas (vendedores técnicos) y ferias especializadas.", "Vallas publicitarias en la carretera.", "Redes sociales de ocio únicamente."], ans: 1, exp: "Se necesita un experto que explique las ventajas técnicas del producto a otro experto (el comprador). " },
    { u: "ADIPLE T3", q: "¿Qué es el 'Branding'?", opts: ["Cocinar carne.", "Proceso de construcción y gestión de una marca.", "Limpiar el almacén.", "Cambiar de oficina."], ans: 1, exp: "Busca que la marca transmita unos valores y sea reconocida y deseada por el mercado. " },
    { u: "ADIPLE T3", q: "La 'Distribución Industrial' suele ser:", opts: ["Muy larga con muchos intermediarios.", "Corta o directa del fabricante al cliente industrial.", "Solo por correo ordinario.", "Inexistente."], ans: 1, exp: "Al ser productos complejos, el contacto directo asegura que el cliente reciba la formación técnica adecuada. " },
    { u: "ADIPLE T3", q: "¿Qué analiza un 'Panel de Detallistas'?", opts: ["La vida de los famosos.", "La evolución de ventas y stocks en puntos de venta minoristas.", "El color de las paredes.", "A los empleados de la fábrica."], ans: 1, exp: "Es una investigación continua que dice qué marcas se están vendiendo más en las tiendas reales. " },
    { u: "ADIPLE T3", q: "El 'Nicho de Mercado' es:", opts: ["Un mercado muy grande para todos.", "Un segmento pequeño y muy específico con necesidades poco satisfechas.", "Un lugar donde se entierran productos fallidos.", "Una marca de ropa."], ans: 1, exp: "Especializarse en un nicho (ej. software solo para dentistas) permite cobrar más y tener menos competencia. " },
    { u: "ADIPLE T3", q: "¿Qué es el 'Neuromarketing'?", opts: ["Vender ordenadores.", "Aplicación de técnicas de neurociencia para entender la reacción del cerebro a estímulos comerciales.", "Hacer trampas.", "Un tipo de medicina."], ans: 1, exp: "Mide cosas como el movimiento de los ojos o el pulso para saber qué llama la atención de verdad. " },
    { u: "ADIPLE T3", q: "El 'Aprovisionamiento' se encarga de:", opts: ["Vender el producto terminado.", "Gestionar la compra y llegada de materiales necesarios para producir.", "Pagar las nóminas.", "Limpiar las máquinas."], ans: 1, exp: "Es vital para que la cadena de montaje no se detenga por falta de un tornillo. " },
    { u: "ADIPLE T3", q: "Un 'Producto Sustitutivo' es aquel que:", opts: ["Es igual que el nuestro.", "Satisface la misma necesidad de forma distinta (ej. tren vs avión).", "Se ha roto.", "Es un regalo."], ans: 1, exp: "Son una amenaza: si el precio de tu producto sube mucho, la gente se pasará al sustitutivo. " },
    { u: "ADIPLE T3", q: "La 'Lealtad de Marca' ocurre cuando:", opts: ["El cliente compra lo más barato.", "El cliente repite la compra de nuestra marca a pesar de otras ofertas.", "Nadie compra el producto.", "La empresa regala cosas."], ans: 1, exp: "Es el objetivo máximo del marketing: tener clientes fieles que no se vayan por un euro de diferencia. " },
    { u: "ADIPLE T3", q: "En una 'Entrevista en Profundidad':", opts: ["Se pregunta a 100 personas a la vez.", "Se mantiene una conversación larga y abierta con un solo individuo.", "Se usan solo gestos.", "No se habla."], ans: 1, exp: "Permite descubrir sentimientos y opiniones que en una encuesta rápida no saldrían. " },
    { u: "ADIPLE T3", q: "¿Qué es el 'Marketing Mix'?", opts: ["Una bebida energética.", "Combinación de Producto, Precio, Distribución y Comunicación (4 Pes).", "Una lista de clientes.", "Un software de diseño."], ans: 1, exp: "Son las cuatro palancas que el director de marketing puede mover para atraer al cliente. " },
    { u: "ADIPLE T3", q: "La 'Obsolescencia Percibida' es:", opts: ["Cuando algo se rompe físicamente.", "Cuando el cliente siente que su producto está pasado de moda aunque funcione bien.", "Un error del motor.", "La fecha de caducidad del yogur."], ans: 1, exp: "Se logra mediante el diseño y la moda (ej. cambiar el color de un móvil cada año). " },
    { u: "ADIPLE T3", q: "El 'Marketing Social' busca:", opts: ["Hacer fiestas.", "Influir en comportamientos para mejorar el bienestar social (ej. no fumar).", "Vender más alcohol.", "Pagar menos impuestos."], ans: 1, exp: "Lo usan ONGs o Gobiernos para concienciar a la población sobre temas importantes. " },
    { u: "ADIPLE T3", q: "Un 'Consumidor Final' es quien:", opts: ["Vende el producto.", "Compra el bien para su propio uso y disfrute.", "Fabrica las piezas.", "Transporta la mercancía."], ans: 1, exp: "Es el último eslabón de la cadena; no usa el producto para ganar dinero, sino para vivir. " },
    { u: "ADIPLE T3", q: "El 'Benchmarking' competitivo consiste en:", opts: ["Copiar al vecino.", "Comparar nuestros procesos con los líderes del sector para mejorar.", "Sentarse en un banco.", "Despedir a los jefes."], ans: 1, exp: "Es aprender de los mejores de forma legal y ética para ser más eficientes. " },
    { u: "ADIPLE T3", q: "¿Qué es una 'Marca Blanca'?", opts: ["Una marca sin nombre.", "Productos vendidos bajo la marca del distribuidor (ej. Hacendado).", "Un producto ilegal.", "Pintura blanca."], ans: 1, exp: "Suelen ser más baratos y compiten directamente con las marcas de fabricante. " },
    { u: "ADIPLE T3", q: "El 'Marketing Viral' se basa en:", opts: ["Contagiar enfermedades.", "Que los propios usuarios compartan el contenido de forma masiva.", "Hacer mucha radio.", "Poner carteles en hospitales."], ans: 1, exp: "Busca que un vídeo o mensaje sea tan bueno que la gente lo pase por WhatsApp o redes sociales solo. " },
    { u: "ADIPLE T3", q: "¿Qué es el 'Street Marketing'?", opts: ["Vender coches.", "Acciones publicitarias originales realizadas en espacios públicos.", "Limpiar la calle.", "Hacer encuestas en casas."], ans: 1, exp: "Busca sorprender al peatón con algo creativo (ej. pintar un paso de cebra como patatas fritas). " },
    { u: "ADIPLE T3", q: "La 'Propuesta de Valor' responde a:", opts: ["¿Cuánto cuesta?", "¿Por qué el cliente debería elegirnos a nosotros y no a la competencia?", "¿Dónde está la tienda?", "¿Quién es el dueño?"], ans: 1, exp: "Es la promesa de beneficios que nos hace únicos y mejores que los demás. " },
    { u: "ADIPLE T3", q: "Un 'Sponsor' o Patrocinador:", opts: ["Es un trabajador.", "Entrega dinero o recursos a un evento a cambio de publicidad.", "Es el cliente final.", "Vende seguros."], ans: 1, exp: "Muy común en deportes para que la marca aparezca en las camisetas. " },
    { u: "ADIPLE T3", q: "El 'Merchandising' se encarga de:", opts: ["Fabricar el producto.", "Promocionar el producto en el propio punto de venta.", "Vender por teléfono.", "Hacer el balance contable."], ans: 1, exp: "Incluye la colocación en estantes, los carteles de oferta y la iluminación de la tienda. " },
    { u: "ADIPLE T3", q: "La 'Logística Inversa' gestiona:", opts: ["Las ventas de ayer.", "Las devoluciones y el reciclaje de productos desde el cliente al fabricante.", "El envío a China.", "La limpieza de la oficina."], ans: 1, exp: "Es clave para la sostenibilidad y para que el cliente esté tranquilo si quiere devolver algo. " },
    { u: "ADIPLE T3", q: "¿Qué es el 'E-commerce'?", opts: ["Comprar en el mercado del barrio.", "Compra y venta de productos o servicios a través de internet.", "Un tipo de motor eléctrico.", "Un impuesto nuevo."], ans: 1, exp: "Ha revolucionado el mundo permitiendo comprar cualquier cosa desde el móvil. " },
    { u: "ADIPLE T3", q: "El 'Marketing de Guerrilla' utiliza:", opts: ["Tanques y armas.", "Técnicas poco convencionales y de bajo coste para gran impacto.", "Mucha televisión.", "Solo prensa escrita."], ans: 1, exp: "Se basa en la creatividad más que en el dinero para llamar la atención. " },
    { u: "ADIPLE T3", q: "La 'Cartera de Productos' es:", opts: ["Un bolso de piel.", "El conjunto de todos los productos que vende una empresa.", "Una lista de precios.", "El dinero en caja."], ans: 1, exp: "Una empresa puede tener una cartera ancha (muchas líneas) o profunda (muchos modelos en una línea). " },
    { u: "ADIPLE T3", q: "Un 'Mercado de Competencia Perfecta' tiene:", opts: ["Un solo vendedor.", "Muchos compradores y vendedores con productos idénticos.", "Precios fijados por ley.", "Productos muy diferentes."], ans: 1, exp: "Es un modelo teórico donde nadie puede influir en el precio; el mercado manda. " },
    { u: "ADIPLE T3", q: "El 'Precio de Penetración' consiste en:", opts: ["Poner el precio más alto del mercado.", "Lanzar el producto con un precio muy bajo para ganar cuota rápido.", "Regalar el producto siempre.", "No poner precio."], ans: 1, exp: "Se usa para entrar en mercados difíciles y que la gente pruebe el producto. " },
    { u: "ADIPLE T3", q: "La 'Venta Personal' es más común en:", opts: ["Venta de chicles.", "Venta de maquinaria industrial compleja y cara.", "Venta por catálogo.", "Venta automática (vending)."], ans: 1, exp: "Requiere que un humano explique, convenza y resuelva dudas técnicas. " },
    { u: "ADIPLE T3", q: "¿Qué es el 'Catering'?", opts: ["Vender gatos.", "Servicio de suministro de comidas y bebidas en eventos.", "Un tipo de marketing.", "Un software de contabilidad."], ans: 1, exp: "Es un servicio del sector terciario muy demandado por las empresas para reuniones. " },
    { u: "ADIPLE T3", q: "La 'Marca Registrada' (®) otorga:", opts: ["El derecho a no pagar impuestos.", "El uso exclusivo del nombre y logotipo legalmente.", "Un premio de calidad.", "La nacionalidad española."], ans: 1, exp: "Protege a la empresa de que otros copien su nombre o engañen al consumidor. " },
    { u: "ADIPLE T3", q: "El 'Marketing de Influencers' usa a:", opts: ["Científicos locos.", "Personas con mucha audiencia y credibilidad en redes sociales.", "Los dueños de la empresa.", "Los políticos."], ans: 1, exp: "Se basa en la confianza que los seguidores tienen en esa persona para recomendar productos. " },
    { u: "ADIPLE T3", q: "¿Qué es el 'Target'?", opts: ["Una tienda de ropa.", "El público objetivo al que se dirige una acción de marketing.", "El nombre del jefe.", "Un error de sistema."], ans: 1, exp: "Es la 'diana' a la que intentamos dar con nuestras flechas publicitarias. " },
    { u: "ADIPLE T3", q: "El 'B2C' (Business to Consumer) se refiere a:", opts: ["Venta entre empresas.", "Venta de la empresa al consumidor final.", "Venta del Estado a la empresa.", "Venta entre amigos."], ans: 1, exp: "Es el marketing de toda la vida: una tienda vendiendo a un particular. " },
    { u: "ADIPLE T3", q: "La 'Estrategia de Especialización' busca:", opts: ["Hacer de todo un poco.", "Centrarse en un solo producto o mercado para ser el mejor en él.", "Vender a todo el mundo.", "No trabajar."], ans: 1, exp: "Permite ser un experto y que los clientes te busquen por tu gran conocimiento específico. " },
    { u: "ADIPLE T3", q: "¿Qué es el 'SEO'?", opts: ["Un gas peligroso.", "Optimización para motores de búsqueda (aparecer arriba en Google gratis).", "Una marca de coches.", "Sueldo Extra Ordinario."], ans: 1, exp: "Es fundamental para que te encuentren en internet sin tener que pagar anuncios cada vez. " },
    { u: "ADIPLE T3", q: "La 'Publicidad Engañosa' es aquella que:", opts: ["Es muy graciosa.", "Induce a error al comprador sobre las características del producto.", "No usa colores.", "Es muy cara."], ans: 1, exp: "Es ilegal y puede acarrear multas muy graves, además de destrozar la reputación de la marca. " },
    { u: "ADIPLE T3", q: "Un 'Folleto' es una herramienta de:", opts: ["Distribución.", "Comunicación (Publicidad).", "Producción.", "Investigación."], ans: 1, exp: "Sirve para dar información física y visual sobre las ofertas en el punto de venta. " },
    { u: "ADIPLE T3", q: "El 'Marketing Directo' utiliza:", opts: ["Vallas en la calle.", "Email, correo postal o teléfono para contactar individualmente al cliente.", "Radio nacional.", "Cine."], ans: 1, exp: "Busca una respuesta inmediata y medible del cliente. " },
    { u: "ADIPLE T3", q: "La 'Matriz de Porter' ayuda a decidir entre:", opts: ["Vender o cerrar.", "Liderazgo en costes, Diferenciación o Enfoque.", "Contratar o despedir.", "Pintar o empapelar."], ans: 1, exp: "Son las tres estrategias genéricas para tener éxito frente a los competidores. " },
    { u: "ADIPLE T3", q: "El 'Análisis de la Competencia' sirve para:", opts: ["Copiar sus errores.", "Conocer sus fortalezas y debilidades para mejorar nuestra estrategia.", "Hacerles amigos.", "No sirve para nada."], ans: 1, exp: "Debes saber qué hacen los demás para poder ofrecer algo mejor o diferente. " },
    { u: "ADIPLE T3", q: "¿Qué es el 'Público Objetivo'?", opts: ["La gente que pasa por la calle.", "El grupo específico de personas con más probabilidades de comprar nuestro producto.", "La familia del dueño.", "Los antiguos empleados."], ans: 1, exp: "Definirlo bien ahorra mucho dinero en marketing al no disparar al aire. " },
    { u: "ADIPLE T3", q: "Una campaña de vacunación del Ministerio de Sanidad es un ejemplo de:", opts: ["Marketing Político.", "Marketing Social.", "Marketing Industrial.", "Marketing de lujo."], ans: 1, exp: "Busca un beneficio para la sociedad y la salud pública, no ganar dinero. " },
    { u: "ADIPLE T3", q: "El 'Benchmarking' consiste en:", opts: ["Copiar ilegalmente planos.", "Comparar los productos y procesos propios con los de los mejores para mejorar.", "Ver pasar el tiempo.", "Poner bancos en la entrada."], ans: 1, exp: "Es una técnica de mejora continua basada en los estándares de los líderes del sector. " },
    { u: "ADIPLE T3", q: "En el ciclo Crear-Medir-Aprender, el paso 'Aprender' sirve para:", opts: ["Olvidar lo pasado.", "Decidir si se debe pivotar (cambiar) o perseverar basándose en datos.", "Castigar fallos.", "Ir a la universidad."], ans: 1, exp: "Es la base de la metodología Lean: usar datos reales para no perder el tiempo en ideas que no funcionan. " },
    { u: "ADIPLE T3", q: "El concepto de 'Propuesta de Valor' es:", opts: ["El precio de venta.", "El conjunto de beneficios que la empresa promete entregar al cliente.", "El capital social.", "El valor de las máquinas."], ans: 1, exp: "Es lo que hace que el cliente diga: 'Vale, esto es lo que necesito y por eso lo compro'. " },
    { u: "ADIPLE T3", q: "¿Cuál es el objetivo final de estudiar marketing y análisis de mercado?", opts: ["Pintar carteles bonitos.", "Comprender el mercado para ofrecer soluciones que satisfagan a los clientes y aseguren la viabilidad.", "Sustituir ingenieros.", "Gastar dinero."], ans: 1, exp: "El marketing es la brújula de la empresa; sin él, la fábrica puede acabar haciendo cosas que nadie quiere comprar. " },
// --- PREGUNTAS DE LA PLATAFORMA (MOODLE) ---
    { u: "ADIPLE T4", q: "¿Cuál de las siguientes NO es una estrategia según la ventaja competitiva?", opts: ["Estrategia de costes.", "Estrategia de diferenciación.", "Estrategia de enfoque.", "Estrategia de diversificación."], ans: 3, exp: "Michael Porter define tres estrategias genéricas: liderazgo en costes, diferenciación y enfoque (o nicho). La diversificación es una estrategia de crecimiento (Matriz de Ansoff), no una ventaja competitiva básica." },
    { u: "ADIPLE T4", q: "¿Cuál de los siguientes no es un criterio para clasificar los datos en el análisis de mercado?", opts: ["Por su naturaleza.", "Por su ubicación.", "Por su fuente.", "Por su costo."], ans: 3, exp: "Los datos se clasifican técnicamente por su naturaleza (cualitativos/cuantitativos), ubicación (internos/externos) o fuente (primarios/secundarios). El costo es un factor logístico, pero no un criterio de clasificación académica de la información." },
    { u: "ADIPLE T4", q: "¿Cuál es la primera fase en el proceso de análisis de mercados?", opts: ["Análisis de la información.", "Búsqueda y obtención de la información.", "Planteamiento de la investigación.", "Obtención y presentación de resultados."], ans: 2, exp: "Antes de recoger o analizar nada, es imprescindible definir el problema, los objetivos de la investigación y las hipótesis de trabajo." },
    { u: "ADIPLE T4", q: "¿Cuál es la principal herramienta del marketing estratégico?", opts: ["La publicidad.", "El análisis DAFO.", "La fijación de precios.", "La distribución logística."], ans: 1, exp: "El DAFO (Debilidades, Amenazas, Fortalezas y Oportunidades) es la herramienta fundamental para diagnosticar la situación de la empresa y diseñar su estrategia a largo plazo." },
    { u: "ADIPLE T4", q: "¿Cuál es una técnica de recogida de información cuantitativa?", opts: ["Dinámicas de grupo.", "Entrevistas en profundidad.", "Encuestas.", "Observación directa cualitativa."], ans: 2, exp: "Las encuestas permiten obtener datos numéricos de muestras amplias para realizar análisis estadísticos, característica propia de la metodología cuantitativa." },
    { u: "ADIPLE T4", q: "¿Qué nombre recibe el grupo de clientes con necesidades similares al que la empresa decide dirigirse?", opts: ["Segmento de mercado.", "Público objetivo o Target.", "Nicho de mercado.", "Mercado potencial."], ans: 1, exp: "El público objetivo es el grupo específico de consumidores sobre el que la empresa centra sus esfuerzos y tácticas de marketing." },
    { u: "ADIPLE T4", q: "¿Qué técnica consiste en simular el comportamiento de los consumidores en un entorno controlado?", opts: ["Entrevista.", "Encuesta.", "Experimentación.", "Panel."], ans: 2, exp: "La experimentación busca establecer relaciones causa-efecto manipulando variables (como el precio o el envase) en un entorno de prueba." },
    { u: "ADIPLE T4", q: "¿Qué tipo de estrategia de crecimiento consiste en vender productos nuevos en mercados nuevos?", opts: ["Penetración de mercado.", "Desarrollo de productos.", "Desarrollo de mercados.", "Diversificación."], ans: 3, exp: "Según la Matriz de Ansoff, la diversificación es la estrategia de mayor riesgo al alejarse de los productos y mercados conocidos por la empresa." },
    { u: "ADIPLE T4", q: "El análisis PESTEL se utiliza para analizar:", opts: ["Las debilidades internas.", "El microentorno de la empresa.", "El macroentorno (factores externos generales).", "La satisfacción del cliente."], ans: 2, exp: "PESTEL analiza factores Políticos, Económicos, Sociales, Tecnológicos, Ecológicos y Legales que afectan a todas las empresas de un territorio." },
    { u: "ADIPLE T4", q: "La segmentación de mercado por criterios demográficos incluye variables como:", opts: ["Personalidad y valores.", "Región y clima.", "Edad, sexo y nivel de ingresos.", "Frecuencia de uso del producto."], ans: 2, exp: "Los criterios demográficos se basan en características objetivas y medibles de la población." },

    // --- BLOQUE CUESTIONARIO DE AUTOEVALUACIÓN (70 PREGUNTAS) ---
    { u: "ADIPLE T4", q: "¿Qué es el 'Marketing Estratégico'?", opts: ["La ejecución de anuncios.", "El análisis de las necesidades del mercado y el diseño de la estrategia a largo plazo.", "La venta directa en tienda.", "El transporte de mercancías."], ans: 1, exp: "Se ocupa de la reflexión previa: definir qué mercados atacar y qué valor diferencial ofrecer." },
    { u: "ADIPLE T4", q: "El 'Marketing Operativo' se centra en:", opts: ["La visión a 10 años.", "Las variables tácticas o Marketing Mix (4 Pes) a corto/medio plazo.", "El análisis DAFO.", "La creación de la misión de la empresa."], ans: 1, exp: "Es el marketing de acción: precios, promociones, producto y distribución." },
    { u: "ADIPLE T4", q: "¿Qué son los 'Datos Secundarios'?", opts: ["Datos obtenidos por primera vez para el estudio.", "Información ya existente que fue recogida para otros propósitos.", "Datos de poca importancia.", "Datos que solo valen un segundo."], ans: 1, exp: "Son fuentes como estadísticas del INE, informes de cámaras de comercio o bases de datos internas previas." },
    { u: "ADIPLE T4", q: "La técnica de 'Mistery Shopping' sirve para:", opts: ["Comprar ropa barata.", "Evaluar la calidad del servicio de forma anónima simulando ser un cliente.", "Hacer inventario.", "Diseñar logotipos."], ans: 1, exp: "Es una técnica de observación útil para medir la atención al cliente y el cumplimiento de estándares." },
    { u: "ADIPLE T4", q: "¿Qué es un 'Panel de Consumidores'?", opts: ["Una reunión de un solo día.", "Una muestra fija de personas que proporcionan información periódica sobre sus compras.", "Un cuadro eléctrico.", "Una encuesta a pie de calle."], ans: 1, exp: "Permite analizar la evolución de los hábitos de consumo a lo largo del tiempo con el mismo grupo de personas." },
    { u: "ADIPLE T4", q: "En la Matriz de Ansoff, la 'Penetración de Mercado' busca:", opts: ["Vender productos nuevos.", "Aumentar las ventas de productos actuales en mercados actuales.", "Vender en China.", "Cerrar la empresa."], ans: 1, exp: "Se logra captando clientes de la competencia o aumentando la frecuencia de consumo de los clientes propios." },
    { u: "ADIPLE T4", q: "La estrategia de 'Desarrollo de Mercados' consiste en:", opts: ["Modificar el producto.", "Llevar productos actuales a nuevas zonas geográficas o nuevos segmentos.", "Bajar los precios.", "Hacer publicidad en radio."], ans: 1, exp: "Es buscar nuevos horizontes (ej. exportación) para lo que ya sabemos fabricar." },
    { u: "ADIPLE T4", q: "¿Qué es la 'Ventaja Competitiva'?", opts: ["Tener muchos trabajadores.", "Cualquier característica que aísle a la empresa de la competencia y la haga superior.", "Tener un local grande.", "Pagar menos impuestos."], ans: 1, exp: "Puede ser el prestigio de marca, una patente, menores costes o una atención al cliente excepcional." },
    { u: "ADIPLE T4", q: "La 'Estrategia de Diferenciación' busca que el cliente perciba el producto como:", opts: ["El más barato.", "Único y superior por su calidad, diseño o servicio.", "Exactamente igual a los demás.", "Inexistente."], ans: 1, exp: "Si el cliente percibe exclusividad, la empresa puede cobrar un precio 'premium' superior a la competencia." },
    { u: "ADIPLE T4", q: "La 'Estrategia de Enfoque o Nicho' consiste en:", opts: ["Vender a todo el mundo por igual.", "Centrarse en un segmento muy específico del mercado para satisfacerlo mejor.", "Hacer fotos con una cámara.", "Contratar a muchos gerentes."], ans: 1, exp: "Se busca ser el mejor en un pequeño rincón del mercado en lugar de ser uno más en el mercado general." },
    { u: "ADIPLE T4", q: "En el análisis DAFO, una 'Oportunidad' es:", opts: ["Algo bueno que hace la empresa dentro.", "Un factor externo positivo del entorno que la empresa puede aprovechar.", "Un error del jefe.", "Un descuento en el banco."], ans: 1, exp: "Por ejemplo, una nueva ley que fomenta el uso de nuestro producto o la quiebra de un rival." },
    { u: "ADIPLE T4", q: "En el análisis DAFO, una 'Debilidad' es:", opts: ["Una amenaza del mercado.", "Un aspecto interno negativo que limita la capacidad de la empresa.", "El cansancio de los obreros.", "La lluvia."], ans: 1, exp: "Son carencias propias como falta de tecnología, mala ubicación o poco capital." },
    { u: "ADIPLE T4", q: "¿Qué analiza el factor 'S' de PESTEL?", opts: ["La Sociedad (cultura, demografía, niveles educativos, etc.).", "La Seguridad industrial.", "El Sueldo de los operarios.", "El Software de gestión."], ans: 0, exp: "Estudia cómo los cambios en los gustos y la estructura de la población afectan al negocio." },
    { u: "ADIPLE T4", q: "La 'Investigación Cualitativa' se caracteriza por usar:", opts: ["Muestras muy grandes y números.", "Muestras pequeñas y técnicas psicológicas para entender el 'porqué'.", "Solo calculadoras.", "Anuncios de televisión."], ans: 1, exp: "Busca profundidad de opinión más que representatividad estadística." },
    { u: "ADIPLE T4", q: "En una encuesta, una 'Pregunta de Filtro' sirve para:", opts: ["Limpiar la información.", "Seleccionar a las personas que cumplen ciertos requisitos para seguir respondiendo.", "Hacer la encuesta más larga.", "Ocultar el objetivo de la investigación."], ans: 1, exp: "Ejemplo: '¿Es usted el responsable de compras?'. Si dice no, termina la encuesta." },
    { u: "ADIPLE T4", q: "La 'Segmentación Psicográfica' divide a los clientes según:", opts: ["Su barrio.", "Su clase social, estilo de vida o personalidad.", "Su edad.", "Su profesión."], ans: 1, exp: "Dos personas de la misma edad y renta pueden comprar distinto por tener diferentes valores o hobbies." },
    { u: "ADIPLE T4", q: "¿Qué es el 'Marketing Relacional'?", opts: ["Hacerse amigo de los proveedores.", "Estrategia para crear, mantener y fortalecer relaciones rentables con los clientes a largo plazo.", "Vender solo a familiares.", "Poner anuncios en redes sociales."], ans: 1, exp: "Cuesta mucho más conseguir un cliente nuevo que mantener a uno actual." },
    { u: "ADIPLE T4", q: "El concepto de 'Posicionamiento' se refiere a la imagen en la mente de:", opts: ["El dueño de la empresa.", "El consumidor.", "El banquero.", "El proveedor."], ans: 1, exp: "Es cómo el cliente nos ve respecto a los demás (ej. Volvo = Seguridad)." },
    { u: "ADIPLE T4", q: "Un 'Mercado Potencial' es:", opts: ["La gente que ya nos compra.", "El conjunto de personas que podrían llegar a necesitar el producto en el futuro.", "La competencia.", "Un mercado con mucha electricidad."], ans: 1, exp: "Representa el límite máximo de ventas que se podría alcanzar si todo saliera perfecto." },
    { u: "ADIPLE T4", q: "La 'Cuota de Mercado' representa:", opts: ["El dinero que la empresa tiene en caja.", "El porcentaje de ventas de nuestra empresa respecto al total del mercado.", "La multa por vender mucho.", "El número de empleados."], ans: 1, exp: "Es el indicador del poder o dominio que tiene una empresa en su sector." },
    { u: "ADIPLE T4", q: "¿Qué es el 'Macroentorno'?", opts: ["El interior de la oficina.", "Factores externos incontrolables que afectan a todas las empresas (ej. leyes, economía).", "La sala de máquinas.", "Los clientes más grandes."], ans: 1, exp: "Se analiza mediante herramientas como el PESTEL." },
    { u: "ADIPLE T4", q: "¿Qué es el 'Microentorno'?", opts: ["Los chips del ordenador.", "Actores cercanos a la empresa que influyen en su actividad (clientes, proveedores, rivales).", "El personal de limpieza.", "Los tornillos pequeños."], ans: 1, exp: "Se suele analizar con el modelo de las 5 fuerzas de Porter." },
    { u: "ADIPLE T4", q: "La estrategia de 'Liderazgo en Costes' requiere:", opts: ["Ser el más elegante.", "Producir de forma muy eficiente para ofrecer los precios más bajos.", "No tener trabajadores.", "Vender solo por internet."], ans: 1, exp: "Permite ganar dinero en mercados donde el precio es el único factor de decisión." },
    { u: "ADIPLE T4", q: "Un 'Error de Muestreo' en una investigación ocurre cuando:", opts: ["La calculadora se rompe.", "La muestra seleccionada no representa bien a la población total.", "Se pierde el papel de la encuesta.", "El encuestador llega tarde."], ans: 1, exp: "Si solo preguntamos a jóvenes sobre un producto para ancianos, el resultado será erróneo." },
    { u: "ADIPLE T4", q: "¿Qué es el 'Branding'?", opts: ["Hacer barbacoas.", "Proceso de creación, diseño y gestión de una marca.", "Limpiar el almacén.", "Cambiar de oficina."], ans: 1, exp: "Busca que el nombre y logo de la empresa transmitan valores y generen confianza." },
    { u: "ADIPLE T4", q: "En la mezcla de comunicación, las 'Relaciones Públicas' buscan:", opts: ["Venta directa agresiva.", "Crear una imagen positiva de la empresa en la sociedad.", "Solo hablar con los amigos.", "Hacer fiestas."], ans: 1, exp: "Incluyen comunicados de prensa, patrocinios y eventos corporativos." },
    { u: "ADIPLE T4", q: "La variable 'Distribución' (Place) se encarga de:", opts: ["Diseñar el envase.", "Hacer que el producto llegue al cliente en el lugar y momento adecuados.", "Pagar a los vendedores.", "Pintar los camiones."], ans: 1, exp: "Define los canales de venta (online, mayoristas, tiendas físicas)." },
    { u: "ADIPLE T4", q: "¿Qué es la 'Segmentación Conductual'?", opts: ["Dividir por la conducta de los trabajadores.", "Dividir a los consumidores según su conocimiento, actitud o uso del producto.", "Observar cómo camina la gente.", "Un examen psicológico."], ans: 1, exp: "Ejemplo: separar a los clientes que compran por 'estatus' de los que compran por 'ahorro'." },
    { u: "ADIPLE T4", q: "Un 'Nicho de Mercado' es un segmento:", opts: ["Muy grande.", "Pequeño y muy especializado con necesidades específicas.", "Donde se entierran empresas.", "Solo para productos de lujo."], ans: 1, exp: "Suele tener menos competencia y permite una mayor fidelización (ej. comida para gatos celíacos)." },
    { u: "ADIPLE T4", q: "La 'Matriz BCG' clasifica los productos según:", opts: ["Color y tamaño.", "Crecimiento del mercado y cuota de mercado relativa.", "Precio y calidad.", "Antigüedad y peso."], ans: 1, exp: "Identifica productos Estrella, Vaca, Interrogante y Perro." },
    { u: "ADIPLE T4", q: "¿Qué es la 'Fidelización del Cliente'?", opts: ["Engañar al cliente para que no se vaya.", "Lograr que el cliente repita la compra y sea leal a la marca.", "Hacerle un regalo una vez.", "No cobrarle las facturas."], ans: 1, exp: "Se basa en la satisfacción y en la creación de vínculos emocionales o de valor." },
    { u: "ADIPLE T4", q: "El 'Marketing Mix' industrial incluye habitualmente:", opts: ["Solo publicidad en radio.", "Producto, Precio, Distribución, Comunicación y a veces Servicio Post-venta.", "Solo el diseño del logo.", "Comprar máquinas baratas."], ans: 1, exp: "En la industria, el mantenimiento y soporte técnico son parte esencial de la oferta comercial." },
    { u: "ADIPLE T4", q: "La 'Observación' como técnica de investigación puede ser:", opts: ["Directa o mecánica (ej. cámaras, contadores de paso).", "Solo por telescopio.", "Solo a través de las redes sociales.", "Ilegal siempre."], ans: 0, exp: "Permite ver el comportamiento real sin preguntar al sujeto, evitando respuestas falsas." },
    { u: "ADIPLE T4", q: "¿Qué es el 'Marketing Social'?", opts: ["Hacer muchas fiestas.", "Uso del marketing para promover comportamientos beneficiosos para la sociedad.", "Vender en redes sociales.", "Pagar el seguro social."], ans: 1, exp: "Ejemplo: campañas contra el tabaco o a favor del reciclaje." },
    { u: "ADIPLE T4", q: "Una variable 'Discreta' en estadística es la que:", opts: ["No cuenta secretos.", "Toma valores enteros (ej. número de hijos, número de coches).", "Se esconde en los informes.", "Vale cualquier número decimal."], ans: 1, exp: "No puede haber 2.5 hijos; son valores cerrados." },
    { u: "ADIPLE T4", q: "El 'Marketing de Guerrilla' se basa en:", opts: ["Usar armas de juguete.", "Técnicas poco convencionales de bajo coste y gran impacto.", "Hacer publicidad en zonas de guerra.", "Solo carteles en la calle."], ans: 1, exp: "Se apoya en la creatividad y la sorpresa para llamar la atención del público." },
    { u: "ADIPLE T4", q: "¿Qué es el 'Benchmarking'?", opts: ["Sentarse en un banco.", "Comparar nuestros procesos y productos con los líderes del sector para mejorar.", "Copiar ilegalmente planos.", "Echar a los competidores."], ans: 1, exp: "Es un proceso continuo de aprendizaje de las mejores prácticas de otros." },
    { u: "ADIPLE T4", q: "En el análisis DAFO, las 'Fortalezas' y 'Debilidades' son de carácter:", opts: ["Externo.", "Interno.", "Financiero únicamente.", "Psicológico."], ans: 1, exp: "Son factores que dependen directamente de la gestión de la propia empresa." },
    { u: "ADIPLE T4", q: "El factor 'T' de PESTEL analiza:", opts: ["El Tiempo meteorológico.", "La Tecnología (innovación, patentes, automatización).", "El Transporte.", "El Tamaño de las empresas."], ans: 1, exp: "Clave para saber si nuestra maquinaria o producto va a quedar obsoleto pronto." },
    { u: "ADIPLE T4", q: "La 'Investigación de Mercados' debe ser objetiva, lo que significa:", opts: ["Que el jefe decida los resultados.", "Que los datos se recojan y analicen sin prejuicios ni opiniones personales.", "Que se usen solo objetos.", "Que sea muy barata."], ans: 1, exp: "La información solo es útil si refleja la realidad, aunque no nos guste." },
    { u: "ADIPLE T4", q: "¿Qué es un 'Canal de Distribución Largo'?", opts: ["Un canal que mide 10 km.", "Aquel con varios intermediarios (mayoristas, minoristas) entre productor y cliente.", "Un canal que tarda un año en entregar.", "Vender solo a través de internet."], ans: 1, exp: "Típico en productos de gran consumo para llegar a miles de puntos de venta." },
    { u: "ADIPLE T4", q: "El 'Targeting' es el proceso de:", opts: ["Pintar dianas.", "Evaluar y seleccionar los segmentos a los que se va a dirigir la empresa.", "Hacer una lista de precios.", "Contratar vendedores."], ans: 1, exp: "Es elegir a quién vamos a intentar venderle de entre todos los grupos posibles." },
    { u: "ADIPLE T4", q: "¿Qué es la 'Obsolescencia Programada'?", opts: ["Cuando algo se rompe sin querer.", "Diseñar productos para que fallen tras un tiempo y obligar a una nueva compra.", "Programar el autómata de fábrica.", "Poner fecha a las vacaciones."], ans: 1, exp: "Es una técnica para mantener el consumo, aunque es muy criticada éticamente." },
    { u: "ADIPLE T4", q: "Un 'Mercado Saturado' es aquel donde:", opts: ["Hay mucha agua.", "La oferta es muy superior a la demanda y ya no hay hueco para nuevos competidores.", "Nadie vende nada.", "El Estado regala los productos."], ans: 1, exp: "En estos mercados la única forma de crecer es robando clientes a la competencia con precios o innovación." },
    { u: "ADIPLE T4", q: "El 'Cuestionario Piloto' sirve para:", opts: ["Que lo respondan los pilotos de avión.", "Probar la encuesta con un grupo pequeño para detectar errores antes de la versión final.", "Hacer una encuesta rápida.", "Elegir al mejor encuestador."], ans: 1, exp: "Ayuda a ver si las preguntas se entienden bien o si alguna opción de respuesta falta." },
    { u: "ADIPLE T4", q: "El 'Marketing Viral' utiliza principalmente:", opts: ["Hospitales y vacunas.", "Las redes sociales para que los usuarios compartan el contenido de forma masiva.", "Anuncios en periódicos.", "Vallas publicitarias gigantes."], ans: 1, exp: "Busca que el mensaje se propague solo, como un virus, gracias al interés de la gente." },
    { u: "ADIPLE T4", q: "La variable 'Producto' en el marketing mix incluye:", opts: ["Solo el objeto físico.", "El objeto, el envase, la marca, la garantía y el servicio post-venta.", "El precio del objeto.", "La tienda donde se vende."], ans: 1, exp: "Es todo el conjunto de beneficios que el cliente recibe al comprar." },
    { u: "ADIPLE T4", q: "¿Qué analiza el factor 'E' de PESTEL?", opts: ["La Energía.", "Los factores Económicos (PIB, inflación, desempleo).", "La Educación.", "El Estilo de vida."], ans: 1, exp: "Indica si el país está en crisis o en crecimiento, lo que afecta a la capacidad de compra." },
    { u: "ADIPLE T4", q: "Un 'Logo' es:", opts: ["Un animal de la selva.", "El símbolo gráfico que identifica a una marca o empresa.", "Un tipo de discurso.", "El nombre del dueño escrito."], ans: 1, exp: "Es una pieza clave de la identidad visual corporativa." },
    { u: "ADIPLE T4", q: "La 'Estrategia de Diversificación Conglomerada' es:", opts: ["Vender más de lo mismo.", "Entrar en negocios totalmente nuevos que no tienen relación con la actividad actual.", "Puntuar a los competidores.", "Unir dos empresas iguales."], ans: 1, exp: "Ejemplo: una empresa de coches que compra una cadena de hoteles." },
    { u: "ADIPLE T4", q: "¿Qué es el 'Showrooming'?", opts: ["Limpiar la habitación.", "Ver un producto en una tienda física para luego comprarlo más barato por internet.", "Hacer un desfile de modelos.", "Vivir en la oficina."], ans: 1, exp: "Es un gran reto para el comercio tradicional frente al e-commerce." },
    { u: "ADIPLE T4", q: "En investigación de mercados, el 'Universo' es:", opts: ["El espacio exterior.", "El conjunto total de individuos que son objeto de estudio.", "Todas las empresas del mundo.", "La competencia únicamente."], ans: 1, exp: "Por ejemplo, si estudio pañales, el universo son todos los padres con bebés del país." },
    { u: "ADIPLE T4", q: "Una 'Marca Blanca' es aquella que:", opts: ["No tiene color.", "Se vende bajo el nombre del distribuidor (ej. Hacendado) y suele ser más barata.", "Es ilegal.", "Pintura de paredes."], ans: 1, exp: "Compiten con las marcas de fabricante ofreciendo una buena relación calidad-precio." },
    { u: "ADIPLE T4", q: "La 'Propuesta de Valor' responde a la pregunta:", opts: ["¿Cuánto cuesta?", "¿Por qué el cliente debe elegirnos a nosotros y no a otro?", "¿Dónde está la fábrica?", "¿Quién es el gerente?"], ans: 1, exp: "Es la promesa de beneficios que nos hace únicos y preferibles." },
    { u: "ADIPLE T4", q: "¿Qué es el 'E-commerce' B2B?", opts: ["Venta de empresa a consumidor final.", "Comercio electrónico entre empresas (negocio a negocio).", "Venta del Estado a empresas.", "Venta entre amigos."], ans: 1, exp: "Muy común en suministros industriales y materias primas." },
    { u: "ADIPLE T4", q: "El factor 'L' de PESTEL se refiere a:", opts: ["Logística.", "Factores Legales (leyes laborales, de seguridad, comercio, etc.).", "Limpieza de la planta.", "Liderazgo gerencial."], ans: 1, exp: "Es vital para cumplir con la normativa y evitar sanciones graves." },
    { u: "ADIPLE T4", q: "La 'Segmentación por Ventajas Buscadas' se fija en:", opts: ["El barrio del cliente.", "El beneficio principal que el cliente espera del producto (ej. economía, estatus, salud).", "La edad del cliente.", "El sexo del cliente."], ans: 1, exp: "Permite diseñar productos que ataquen necesidades específicas de diferentes grupos." },
    { u: "ADIPLE T4", q: "Un 'Producto Interrogante' en la matriz BCG es aquel que:", opts: ["Nadie sabe qué es.", "Tiene baja cuota en un mercado que crece mucho (no se sabe si triunfará).", "Es el más antiguo.", "No tiene precio."], ans: 1, exp: "Requieren mucha inversión para intentar convertirlos en productos 'Estrella'." },
    { u: "ADIPLE T4", q: "¿Qué es el 'Cross-selling' o Venta Cruzada?", opts: ["Vender enfadado.", "Ofrecer productos complementarios al que el cliente está comprando (ej. funda para el móvil).", "Vender a la competencia.", "Cambiar el producto por otro."], ans: 1, exp: "Aumenta el valor medio de la compra y la satisfacción del cliente." },
    { u: "ADIPLE T4", q: "La 'Publicidad Engañosa' es aquella que:", opts: ["Es muy divertida.", "Omite datos o induce a error al comprador sobre las características del bien.", "No usa colores.", "Es muy barata de hacer."], ans: 1, exp: "Está prohibida y penalizada por la ley de defensa de los consumidores." },
    { u: "ADIPLE T4", q: "Un 'Mercado Global' implica que la empresa:", opts: ["Solo vende en su pueblo.", "Considera al mundo entero como su mercado potencial.", "Usa globos para publicidad.", "No tiene competencia."], ans: 1, exp: "La globalización y el transporte facilitan que una pyme pueda exportar a cualquier continente." },
    { u: "ADIPLE T4", q: "El 'CRM' (Customer Relationship Management) es un software para:", opts: ["Fabricar piezas.", "Gestionar toda la información y relación con los clientes de forma organizada.", "Calcular la nómina.", "Jugar a videojuegos."], ans: 1, exp: "Ayuda a conocer mejor al cliente para ofrecerle lo que necesita en el momento justo." },
    { u: "ADIPLE T4", q: "¿Qué es la 'Estrategia de Descremación' de precios?", opts: ["Vender leche.", "Lanzar el producto a un precio muy alto para captar a los clientes que más valoran la novedad.", "Bajar los precios al mínimo desde el principio.", "Regalar el producto."], ans: 1, exp: "Típico en tecnología (ej. iPhones), el precio baja meses después para llegar al resto del mercado." },
    { u: "ADIPLE T4", q: "La 'Lealtad de Marca' ocurre cuando el cliente:", opts: ["Compra lo primero que ve.", "Repite la compra de nuestra marca por convicción, aunque haya ofertas de otros.", "No compra nada.", "Se queja siempre."], ans: 1, exp: "Es el activo más valioso de una empresa a largo plazo." },
    { u: "ADIPLE T4", q: "¿Qué analiza el factor 'E' (Ecológico) de PESTEL?", opts: ["El ahorro de dinero.", "Leyes ambientales, cambio climático y sostenibilidad.", "El color de las máquinas.", "La higiene de los empleados."], ans: 1, exp: "Cada vez más importante por la presión social y las normativas de reciclaje y emisiones." },
    { u: "ADIPLE T4", q: "Un 'Proveedor Único' supone para la empresa:", opts: ["Un ahorro total.", "Un riesgo alto de dependencia y falta de negociación.", "Una ventaja competitiva.", "No importa nada."], ans: 1, exp: "Si el proveedor tiene problemas o sube precios, la empresa se queda bloqueada." },
    { u: "ADIPLE T4", q: "El 'Merchandising' es el marketing aplicado al:", opts: ["Despacho del director.", "Punto de venta físico para incentivar la compra (colocación, carteles).", "Transporte por camión.", "Diseño de la fábrica."], ans: 1, exp: "Incluye la iluminación, la música de la tienda y las islas de productos en oferta." },
    { u: "ADIPLE T4", q: "La 'Matriz de Porter' ayuda a elegir la estrategia para:", opts: ["Vender más barato.", "Enfrentarse a la competencia y obtener una posición rentable.", "Contratar personal.", "Pagar impuestos."], ans: 1, exp: "Liderazgo en costes, diferenciación o enfoque." },
    { u: "ADIPLE T4", q: "El 'Sponsoring' o Patrocinio consiste en:", opts: ["Ser el jefe.", "Apoyar un evento o persona a cambio de que aparezca nuestra marca.", "Comprar una empresa pequeña.", "Vender a través de intermediarios."], ans: 1, exp: "Muy usado en deportes para asociar la marca a valores de esfuerzo o éxito." },
    { u: "ADIPLE T4", q: "El objetivo final de toda la estrategia de marketing es:", opts: ["Engañar al cliente.", "Satisfacer las necesidades del cliente de forma rentable y sostenible para la empresa.", "Gastar el presupuesto anual.", "Hacer fotos bonitas de los productos."], ans: 1, exp: "El marketing busca el beneficio mutuo: que el cliente solucione su problema y la empresa gane dinero para seguir existiendo." },
// --- PREGUNTAS DE LA PLATAFORMA (MOODLE) ---
    { u: "ADIPLE T5", q: "Al responsable de recursos humanos se le presuponen varias habilidades, entre ellas:", opts: ["Tener motivación y ser capaz de trasmitirla al equipo.", "Comunicar efectivamente.", "Ser resolutivo y determinado en la toma de decisiones.", "Todas son correctas."], ans: 3, exp: "El director de RRHH debe combinar habilidades de liderazgo, comunicación asertiva y capacidad ejecutiva para gestionar el talento de la organización de forma eficiente." },
    { u: "ADIPLE T5", q: "Calcular las nóminas y realizar el pago a los trabajadores se ubica dentro de la siguiente función:", opts: ["Función de empleo.", "Función de administración del personal.", "Función de retribución o contraprestación de servicios.", "Función de desarrollo y servicios sociales."], ans: 2, exp: "La función de retribución engloba todo lo relativo a la compensación económica (salarios, incentivos, beneficios sociales) que recibe el trabajador por su labor." },
    { u: "ADIPLE T5", q: "El modelo de gestión por competencias forma parte de los:", opts: ["Modelos tradicionales.", "Modelos actuales.", "Modelos históricos.", "Ninguna es correcta."], ans: 1, exp: "Los modelos actuales de RRHH se centran en el desarrollo de las competencias (conocimientos, habilidades y actitudes) de los individuos para aportar valor estratégico a la empresa." },
    { u: "ADIPLE T5", q: "El plan de actuación, para que el nuevo empleado se integre correctamente en la empresa, se llama:", opts: ["Plan de salida.", "Plan de reclutamiento.", "Plan de acogida.", "Plan de jubilación."], ans: 2, exp: "El plan de acogida es la fase final del proceso de selección que busca que el trabajador se adapte rápido a la cultura, normas y compañeros de la organización." },
    { u: "ADIPLE T5", q: "El proceso que nos permite obtener información acerca de un puesto de trabajo se denomina:", opts: ["Entrevista de salida.", "Análisis de puestos de trabajo.", "Valoración de sueldos.", "Formación interna."], ans: 1, exp: "El análisis de puestos es el procedimiento técnico para identificar las tareas, responsabilidades y requisitos de cada rol dentro de la estructura empresarial." },
    { u: "ADIPLE T5", q: "¿Cuál de las siguientes no es una etapa del análisis de puestos de trabajo?", opts: ["Etapa de preparación.", "Etapa de ejecución.", "Etapa de formación.", "Etapa de presentación."], ans: 2, exp: "Las etapas estándar son: Preparación (planificar), Ejecución (recoger datos) y Presentación (informe final). La formación es un proceso posterior derivado del análisis, pero no una etapa de este." },
    { u: "ADIPLE T5", q: "¿Qué nombre recibe el documento que resume los requisitos humanos del puesto (aptitudes, experiencia, personalidad)?", opts: ["Descripción del puesto.", "Profesiograma o especificación del puesto.", "Contrato de trabajo.", "Manual de prevención."], ans: 1, exp: "El profesiograma detalla el perfil psicológico, físico y de conocimientos que debe tener el candidato ideal para ocupar el puesto analizado." },
    { u: "ADIPLE T5", q: "¿Qué técnica de análisis consiste en que el trabajador anote diariamente sus tareas y el tiempo dedicado?", opts: ["Entrevista.", "Cuestionario.", "Diario o bitácora de trabajo.", "Observación directa."], ans: 2, exp: "El diario de actividades es una técnica de auto-informe muy útil para puestos con tareas variables a lo largo de la jornada o la semana." },
    { u: "ADIPLE T5", q: "La gestión de los expedientes del personal y el cumplimiento de la legalidad laboral corresponde a la:", opts: ["Función de empleo.", "Función de administración del personal.", "Función de seguridad y salud.", "Función de formación."], ans: 1, exp: "La administración de personal se encarga del control de contratos, bajas, permisos y de asegurar que la empresa cumple con la normativa laboral vigente." },
    { u: "ADIPLE T5", q: "Un objetivo operativo de la gestión de RRHH es:", opts: ["Mejorar la calidad de vida de los socios.", "Garantizar la disponibilidad del personal adecuado en el momento preciso.", "Pagar menos impuestos.", "Sustituir a los clientes."], ans: 1, exp: "A nivel operativo, RRHH debe asegurar que cada puesto de la cadena de producción o servicio esté cubierto por la persona capacitada para ello." },

    // --- BLOQUE CUESTIONARIO DE AUTOEVALUACIÓN (70 PREGUNTAS) ---
    { u: "ADIPLE T5", q: "¿Qué es el 'Capital Humano'?", opts: ["El dinero que la empresa tiene en el banco.", "El conjunto de conocimientos, habilidades y experiencias de los empleados.", "Las máquinas de la fábrica.", "El valor de las acciones de la sociedad."], ans: 1, exp: "Se considera el activo más valioso de las organizaciones modernas, ya que es el único factor capaz de innovar y mejorar procesos." },
    { u: "ADIPLE T5", q: "La función de 'Desarrollo de RRHH' incluye actividades como:", opts: ["Limpiar las oficinas.", "Formación, planes de carrera y evaluación del potencial.", "Coser los uniformes.", "Vigilar la puerta de entrada."], ans: 1, exp: "Busca el crecimiento profesional de los trabajadores dentro de la empresa para aumentar su compromiso y productividad." },
    { u: "ADIPLE T5", q: "¿Qué significa que el departamento de RRHH sea un órgano de 'Staff'?", opts: ["Que manda sobre todos los operarios directamente.", "Que asesora y apoya a la dirección y a los demás departamentos sin autoridad lineal.", "Que se encarga solo de la limpieza.", "Que no tiene ninguna función."], ans: 1, exp: "RRHH funciona como consultoría interna, ayudando a los jefes de sección a gestionar a sus propios equipos de forma profesional." },
    { u: "ADIPLE T5", q: "El 'Reclutamiento Interno' consiste en:", opts: ["Contratar a gente de la calle.", "Buscar candidatos para un puesto vacante entre los propios empleados de la empresa.", "Hacer una fiesta para los socios.", "Poner anuncios en el periódico local."], ans: 1, exp: "Favorece la motivación y aprovecha el conocimiento que el trabajador ya tiene sobre el funcionamiento de la casa." },
    { u: "ADIPLE T5", q: "Una ventaja del reclutamiento externo es:", opts: ["Es más barato.", "Aporta 'sangre nueva' e ideas frescas a la organización.", "No requiere entrevistas.", "Es inmediato."], ans: 1, exp: "Permite incorporar talento con experiencias de otras empresas y sectores que pueden enriquecer los procesos internos." },
    { u: "ADIPLE T5", q: "¿Cuál es el objetivo principal de la entrevista de selección?", opts: ["Ver si el candidato es amable.", "Contrastar si el perfil del candidato se ajusta a los requerimientos del puesto.", "Pagar el salario mínimo.", "Hacer perder el tiempo."], ans: 1, exp: "Es el momento de verificar cara a cara si los datos del currículum son ciertos y si la personalidad del aspirante encaja con el equipo." },
    { u: "ADIPLE T5", q: "¿Qué es una 'Competencia' laboral?", opts: ["Ganar una carrera.", "Conjunto de conocimientos, habilidades y actitudes necesarios para desempeñar una tarea.", "El nombre de una empresa rival.", "Un premio en metálico."], ans: 1, exp: "La gestión por competencias busca personas que 'sepan', 'puedan' y 'quieran' realizar el trabajo de forma excelente." },
    { u: "ADIPLE T5", q: "La 'Descripción del Puesto' (Job Description) detalla:", opts: ["La vida personal del trabajador.", "Las tareas, deberes y responsabilidades del puesto.", "El color de las paredes de la oficina.", "Los nombres de los clientes."], ans: 1, exp: "Es el documento que aclara al trabajador exactamente qué es lo que se espera que haga en su día a día." },
    { u: "ADIPLE T5", q: "La técnica de 'Observación Directa' es más eficaz en puestos de:", opts: ["Alta dirección.", "Tareas repetitivas, manuales y mecánicas.", "Investigadores científicos.", "Escritores."], ans: 1, exp: "Permite ver los movimientos físicos y tiempos necesarios en cadenas de montaje o almacenes sin interferir en la labor." },
    { u: "ADIPLE T5", q: "Un inconveniente de los 'Cuestionarios' de análisis de puestos es:", opts: ["Son muy rápidos.", "La información puede ser sesgada o exagerada por el trabajador.", "No se pueden usar con mucha gente.", "Son ilegales."], ans: 1, exp: "El trabajador puede tender a 'inflar' sus responsabilidades para parecer más importante o pedir un aumento de sueldo." },
    { u: "ADIPLE T5", q: "¿Qué es el 'Manual de Funciones' de una empresa?", opts: ["Un libro de chistes.", "Documento que recopila todas las descripciones de puestos de la organización.", "La lista de la compra del comedor.", "El manual de instrucciones del torno."], ans: 1, exp: "Es la 'biblia' administrativa que define quién hace qué y quién manda sobre quién en toda la estructura." },
    { u: "ADIPLE T5", q: "La 'Valoración de Puestos' sirve para:", opts: ["Echar a la gente.", "Determinar el valor relativo de cada puesto para fijar una estructura salarial justa.", "Saber el precio de las mesas.", "Hacer fotos al personal."], ans: 1, exp: "Asegura que a igual responsabilidad y dificultad corresponda igual remuneración, evitando discriminaciones." },
    { u: "ADIPLE T5", q: "¿Qué analiza el factor 'Esfuerzo Mental' en un puesto de trabajo?", opts: ["La fuerza de los brazos.", "La atención, concentración y toma de decisiones requeridas.", "El tiempo de sueño.", "Los gustos musicales."], ans: 1, exp: "Es clave en puestos de control de procesos (como operadores de sala de control) donde el agotamiento no es físico sino psicológico." },
    { u: "ADIPLE T5", q: "Las 'Relaciones Laborales' se ocupan de:", opts: ["Hacer ventas por teléfono.", "La comunicación con los sindicatos y representantes de los trabajadores.", "Vender acciones de la empresa.", "Organizar el viaje de fin de curso."], ans: 1, exp: "Gestionan la negociación colectiva y resuelven conflictos para mantener un clima de paz social en la fábrica." },
    { u: "ADIPLE T5", q: "Un 'Incentivo' laboral es:", opts: ["Una multa por llegar tarde.", "Una gratificación económica o no económica ligada al cumplimiento de objetivos.", "El uniforme de la empresa.", "El café gratis."], ans: 1, exp: "Su fin es motivar al personal para superar los estándares de rendimiento establecidos." },
    { u: "ADIPLE T5", q: "La 'Rotación de Personal' excesiva indica:", opts: ["Que la empresa crece mucho.", "Problemas en el clima laboral, salarios bajos o mala selección.", "Que los trabajadores están muy contentos.", "Que no hace falta personal."], ans: 1, exp: "Un alto índice de bajas voluntarias es un coste enorme para la empresa por la pérdida de experiencia y costes de selección constante." },
    { u: "ADIPLE T5", q: "¿Qué es el 'Ausentismo' laboral?", opts: ["Llegar temprano.", "Incumplimiento de la jornada laboral por faltas al trabajo o retrasos.", "Irse de vacaciones pagadas.", "Trabajar desde casa."], ans: 1, exp: "Afecta gravemente a la productividad, especialmente en procesos industriales en cadena." },
    { u: "ADIPLE T5", q: "La 'Evaluación del Desempeño' mide:", opts: ["La inteligencia del trabajador.", "El cumplimiento de los objetivos y la conducta del trabajador en su puesto.", "El peso del empleado.", "Su antigüedad únicamente."], ans: 1, exp: "Sirve para detectar necesidades de formación, dar feedback al empleado y decidir promociones." },
    { u: "ADIPLE T5", q: "¿Qué significa el término 'Outplacement'?", opts: ["Contratar fuera del país.", "Servicio de apoyo y recolocación para trabajadores que han sido despedidos.", "Limpiar el almacén.", "Comprar ordenadores nuevos."], ans: 1, exp: "Es una práctica de RSC que ayuda a que la salida del trabajador sea lo más traumática posible, mejorando la imagen de la empresa." },
    { u: "ADIPLE T5", q: "La 'Seguridad y Salud Laboral' (Prevención) busca:", opts: ["Evitar que los trabajadores se cansen.", "Prevenir accidentes de trabajo y enfermedades profesionales.", "Pagar seguros médicos caros.", "Que no haya herramientas en el suelo."], ans: 1, exp: "Es una obligación legal (Ley de PRL) fundamental en entornos industriales con máquinas y electricidad." },
    { u: "ADIPLE T5", q: "¿Qué es el 'Turnover'?", opts: ["Un tipo de repuesto.", "El índice de rotación de trabajadores en un periodo.", "La velocidad de la cinta transportadora.", "El cambio de nombre de la empresa."], ans: 1, exp: "Mide cuánta gente entra y sale de la empresa; un turnover sano permite renovar ideas sin perder estabilidad." },
    { u: "ADIPLE T5", q: "El 'Clima Organizacional' se refiere a:", opts: ["La temperatura de la oficina.", "La percepción de los empleados sobre su ambiente de trabajo.", "El tiempo meteorológico en la fábrica.", "La marca de los equipos de aire."], ans: 1, exp: "Un buen clima mejora la satisfacción, reduce el ausentismo y fomenta la colaboración entre departamentos." },
    { u: "ADIPLE T5", q: "¿Qué analiza la 'Ergonomía' en un puesto de trabajo?", opts: ["El sueldo acumulado.", "La adaptación de las herramientas y el entorno a las capacidades del trabajador.", "El color de la marca.", "La vida privada de los jefes."], ans: 1, exp: "Busca evitar lesiones posturales o fatiga física mediante sillas correctas, iluminación adecuada y herramientas cómodas." },
    { u: "ADIPLE T5", q: "Un 'Anuncio de Empleo' profesional debe incluir:", opts: ["Solo el nombre de la empresa.", "El perfil buscado, las tareas principales y los beneficios ofrecidos.", "La lista de todos los empleados actuales.", "Ninguna información importante."], ans: 1, exp: "Actúa como primer filtro para atraer solo a aquellos candidatos que cumplen los requisitos mínimos." },
    { u: "ADIPLE T5", q: "¿Qué es una 'Prueba Psicotécnica'?", opts: ["Un examen de sangre.", "Test diseñado para medir capacidades intelectuales, aptitudes o rasgos de personalidad.", "Una carrera de obstáculos física.", "Un interrogatorio policial."], ans: 1, exp: "Ayuda a predecir el comportamiento del candidato ante situaciones de estrés o resolución de problemas lógicos." },
    { u: "ADIPLE T5", q: "La 'Formación Continua' sirve para:", opts: ["Pasar el tiempo.", "Mantener actualizados los conocimientos del personal ante cambios tecnológicos.", "Gastar el presupuesto sobrante.", "Aprender a cocinar."], ans: 1, exp: "Es vital en el sector industrial donde los PLCs, robots y normativas cambian cada pocos años." },
    { u: "ADIPLE T5", q: "¿Qué es la 'Cultura de Empresa'?", opts: ["La biblioteca del edificio.", "Conjunto de valores, creencias y normas compartidas por los miembros de la organización.", "La nacionalidad de los socios.", "El número de ordenadores."], ans: 1, exp: "Es la personalidad de la empresa: 'Cómo se hacen las cosas aquí'." },
    { u: "ADIPLE T5", q: "El 'Liderazgo' en RRHH se define como:", opts: ["Mandar y castigar.", "Capacidad de influir en otros para que trabajen con entusiasmo por un objetivo común.", "Ser el dueño de la empresa.", "Tener el despacho más grande."], ans: 1, exp: "Un buen líder motiva y guía, no solo da órdenes; es fundamental para la cohesión de los equipos de mantenimiento." },
    { u: "ADIPLE T5", q: "¿Qué es el 'Empowerment'?", opts: ["Dar electricidad a las máquinas.", "Delegar autoridad y responsabilidad a los trabajadores para que tomen decisiones.", "Comprar baterías nuevas.", "Hacer ejercicio físico."], ans: 1, exp: "Aumenta la autonomía del técnico y agiliza la resolución de problemas a pie de máquina." },
    { u: "ADIPLE T5", q: "La 'Negociación Colectiva' da lugar a:", opts: ["Un contrato individual.", "El Convenio Colectivo (norma que regula condiciones de trabajo de un sector o empresa).", "La liquidación del IVA.", "Un folleto publicitario."], ans: 1, exp: "Es el acuerdo entre patronal y sindicatos sobre sueldos, horarios y vacaciones para todos los empleados." },
    { u: "ADIPLE T5", q: "Un 'Analista de Puestos' externo es útil para:", opts: ["Despedir gente sin que el jefe se sienta mal.", "Aportar objetividad y evitar vicios o favoritismos internos en la descripción.", "Ahorrar dinero.", "Limpiar los archivos."], ans: 1, exp: "Al no conocer personalmente a los trabajadores, el analista externo se centra únicamente en la tarea y los datos técnicos." },
    { u: "ADIPLE T5", q: "¿Qué es el 'Teletrabajo'?", opts: ["Vigilar la televisión.", "Realizar la actividad laboral a distancia mediante el uso de tecnologías de información.", "Vender televisores.", "Trabajar solo de noche."], ans: 1, exp: "Permite mayor flexibilidad, aunque en mantenimiento industrial es limitado por la necesidad de tocar las máquinas." },
    { u: "ADIPLE T5", q: "El 'Brainstorming' o tormenta de ideas sirve para:", opts: ["Provocar lluvia artificial.", "Generar gran cantidad de ideas creativas en grupo sobre un problema.", "Pelearse entre compañeros.", "Dormir en la oficina."], ans: 1, exp: "Es una técnica grupal muy potente para buscar soluciones a averías crónicas o mejorar la seguridad." },
    { u: "ADIPLE T5", q: "¿Qué analiza el factor 'Condiciones Ambientales' en el análisis de puestos?", opts: ["La ecología mundial.", "Factores como ruido, temperatura, iluminación y riesgos de accidentes del entorno.", "La decoración de las paredes.", "El precio del aire acondicionado."], ans: 1, exp: "Indica si el puesto requiere pluses de peligrosidad, toxicidad o ropa de protección especial." },
    { u: "ADIPLE T5", q: "La 'Retención del Talento' busca:", opts: ["Impedir físicamente que la gente se vaya.", "Fidelizar a los mejores empleados ofreciéndoles crecimiento y bienestar.", "Pagar el salario mínimo.", "Esconder las llaves de la oficina."], ans: 1, exp: "Busca que los expertos no se lleven su 'know-how' (saber hacer) a la competencia." },
    { u: "ADIPLE T5", q: "¿Qué es el 'Feed-back'?", opts: ["Comida para animales.", "Información de retorno sobre el desempeño de una persona para que pueda mejorar.", "Un tipo de motor.", "El ruido de un altavoz."], ans: 1, exp: "Es la herramienta básica de comunicación jefe-empleado para corregir errores de forma constructiva." },
    { u: "ADIPLE T5", q: "El 'Engagement' laboral es:", opts: ["Un tipo de contrato de boda.", "El compromiso emocional e implicación del trabajador con la empresa.", "El nombre de una máquina.", "Gastar mucha luz."], ans: 1, exp: "Un empleado comprometido rinde más, se accidenta menos y cuida mejor las herramientas." },
    { u: "ADIPLE T5", q: "¿Qué son los 'Servicios Sociales' de la empresa?", opts: ["La policía.", "Beneficios extra como guardería, seguro médico o tickets restaurante.", "Hacer encuestas en la calle.", "Limpiar el barrio."], ans: 1, exp: "Son formas de 'salario emocional' que mejoran la calidad de vida del empleado y su familia." },
    { u: "ADIPLE T5", q: "La 'Motivación Intrínseca' proviene de:", opts: ["El dinero del sueldo.", "La propia satisfacción personal que produce realizar bien el trabajo.", "Los premios del jefe.", "Las amenazas de despido."], ans: 1, exp: "Es la más potente y duradera: el técnico disfruta arreglando máquinas porque le apasiona la tecnología." },
    { u: "ADIPLE T5", q: "¿Qué es el 'Head-hunting'?", opts: ["Cazar animales salvajes.", "Búsqueda directa y captación de directivos o perfiles muy especializados.", "Limpiar las cabezas de los motores.", "Un tipo de sombrero industrial."], ans: 1, exp: "Los 'cazatalentos' buscan a gente que ya está trabajando y no busca empleo, para convencerlos de cambiar de empresa." },
    { u: "ADIPLE T5", q: "En la gestión de RRHH, el 'Expediente' contiene:", opts: ["Solo el nombre.", "Vida laboral, contratos, títulos, sanciones y méritos de cada empleado.", "La lista de la compra.", "Planos de la fábrica."], ans: 1, exp: "Es el historial completo del trabajador desde que entra hasta que sale de la organización." },
    { u: "ADIPLE T5", q: "La 'Comunicación Ascendente' fluye desde:", opts: ["El director a los operarios.", "Los trabajadores hacia sus superiores o dirección.", "El banco a la empresa.", "Entre trabajadores del mismo nivel."], ans: 1, exp: "Es vital para que la gerencia conozca los problemas reales de la planta y las sugerencias de mejora." },
    { u: "ADIPLE T5", q: "¿Qué es el 'Job Enlargement' (Ampliación del puesto)?", opts: ["Hacer la mesa más grande.", "Añadir más tareas del mismo nivel de complejidad al puesto.", "Aumentar el sueldo.", "Trabajar 12 horas."], ans: 1, exp: "Evita la monotonía al dar variedad de tareas al trabajador dentro de su misma categoría." },
    { u: "ADIPLE T5", q: "La 'Gestión del Conocimiento' busca:", opts: ["Ocultar los planos.", "Capturar, compartir y usar el saber de los expertos para beneficio de toda la empresa.", "Hacer exámenes cada día.", "No contratar a nadie nuevo."], ans: 1, exp: "Garantiza que si el jefe de mantenimiento se jubila, sus 'trucos' y conocimientos sigan grabados en la empresa." },
    { u: "ADIPLE T5", q: "Un 'Conflicto Laboral' es:", opts: ["Una pelea física siempre.", "Diferencia de intereses o desacuerdo entre trabajadores o entre estos y la empresa.", "Un error en una factura.", "Un cortocircuito eléctrico."], ans: 1, exp: "Si se gestiona bien, el conflicto puede ser una oportunidad para mejorar las normas de trabajo." },
    { u: "ADIPLE T5", q: "¿Qué es el 'Burn-out' o síndrome del trabajador quemado?", opts: ["Incendio en la ropa de trabajo.", "Estado de agotamiento emocional, físico y mental causado por estrés laboral crónico.", "Que hace mucho calor en la fábrica.", "Tener mucha fiebre."], ans: 1, exp: "Es un riesgo psicosocial grave que el departamento de RRHH debe prevenir vigilando las cargas de trabajo." },
    { u: "ADIPLE T5", q: "La 'Selección por Valores' busca personas que:", opts: ["Tengan mucho dinero.", "Compartan la ética y principios de la cultura de la empresa.", "Solo tengan buenos títulos.", "Sean de la misma familia."], ans: 1, exp: "Es más fácil enseñar a programar un PLC que enseñar a una persona a ser honesta o responsable." },
    { u: "ADIPLE T5", q: "¿Qué es la 'Responsabilidad Social Corporativa' (RSC) en RRHH?", opts: ["Pagar impuestos.", "Prácticas éticas con los empleados, fomento de la igualdad y conciliación.", "Hacer fiestas.", "Tener muchos socios."], ans: 1, exp: "Mejora la reputación de la empresa y atrae a los mejores candidatos del mercado." },
    { u: "ADIPLE T5", q: "El 'Perfil Profesiográfico' se representa gráficamente con:", opts: ["Una foto del trabajador.", "Un gráfico de radar o barras con los niveles requeridos de cada competencia.", "Un dibujo de la máquina.", "Un mapa de la oficina."], ans: 1, exp: "Permite comparar visualmente el perfil del candidato con el perfil ideal del puesto (gap analysis)." },
    { u: "ADIPLE T5", q: "La 'Movilidad Funcional' es la capacidad de:", opts: ["Caminar rápido.", "Cambiar al trabajador de funciones dentro de los límites legales.", "Mover las máquinas de sitio.", "Ir en coche al trabajo."], ans: 1, exp: "Permite a la empresa adaptarse a picos de producción cambiando a gente de una línea a otra." },
    { u: "ADIPLE T5", q: "¿Qué es el 'Salario Emocional'?", opts: ["Llorar al recibir la nómina.", "Beneficios no económicos que mejoran la satisfacción (horario flexible, reconocimiento, buen ambiente).", "Un poema del jefe.", "No cobrar nada."], ans: 1, exp: "A veces un 'gracias' o poder salir antes un viernes motiva más que una pequeña subida de dinero." },
    { u: "ADIPLE T5", q: "La 'Detección de Necesidades de Formación' (DNF) sirve para:", opts: ["Saber quién es el más listo.", "Identificar qué conocimientos faltan al personal para realizar bien su trabajo.", "Echar a los que no saben.", "Vender cursos."], ans: 1, exp: "Es el paso previo para diseñar un plan de formación útil y no gastar dinero en cursos que no se necesitan." },
    { u: "ADIPLE T5", q: "Un 'Accidente de Trabajo' es el que ocurre:", opts: ["Solo en la fábrica.", "Con ocasión o por consecuencia del trabajo realizado por cuenta ajena.", "En casa el fin de semana.", "De vacaciones."], ans: 1, exp: "Incluye los accidentes 'in itinere' (al ir o volver del trabajo) y los ocurridos durante la jornada laboral." },
    { u: "ADIPLE T5", q: "¿Qué significa 'Aptitud física' en el profesiograma?", opts: ["Ser guapo.", "Requerimientos de fuerza, destreza manual o resistencia necesarios para el puesto.", "Gozar de buena salud mental.", "Hacer deporte en el tiempo libre."], ans: 1, exp: "Fundamental para puestos de mantenimiento donde hay que cargar motores o subir a alturas." },
    { u: "ADIPLE T5", q: "La 'Sindicación' es el derecho de los trabajadores a:", opts: ["No ir a trabajar.", "Fundar y afiliarse a sindicatos para defender sus intereses.", "Pintar grafittis.", "Votar al presidente del gobierno."], ans: 1, exp: "Es un derecho fundamental recogido en la Constitución Española y el Estatuto de los Trabajadores." },
    { u: "ADIPLE T5", q: "¿Qué es un 'Canal de Comunicación Informal'?", opts: ["El correo electrónico oficial.", "El boca a boca, los rumores o charlas en el café.", "El tablón de anuncios.", "La revista de la empresa."], ans: 1, exp: "Aunque no sea oficial, transmite información muy rápido y RRHH debe saber gestionarlo para evitar malos entendidos." },
    { u: "ADIPLE T5", q: "La 'Conciliación Vida Laboral y Familiar' permite:", opts: ["Trabajar todo el día.", "Equilibrar las responsabilidades del trabajo con las necesidades de la vida privada.", "Vivir en la empresa.", "No tener hijos."], ans: 1, exp: "Fomenta la felicidad del trabajador y reduce el ausentismo y el estrés." },
    { u: "ADIPLE T5", q: "¿Qué analiza el factor 'Responsabilidad por Maquinaria'?", opts: ["El precio de la máquina.", "El cuidado y mantenimiento que el trabajador debe observar sobre sus herramientas de trabajo.", "Limpiar el suelo de la nave.", "Saber el nombre del fabricante."], ans: 1, exp: "Un operario de una máquina de un millón de euros tiene una responsabilidad mucho mayor que uno que usa un destornillador." },
    { u: "ADIPLE T5", q: "El 'Reclutamiento 2.0' utiliza:", opts: ["Cables de red.", "Redes sociales profesionales y portales de empleo en internet (ej. LinkedIn).", "Anuncios en la televisión.", "Megáfonos en la calle."], ans: 1, exp: "Agiliza la búsqueda y permite acceder a candidatos 'pasivos' que no están buscando empleo activamente." },
    { u: "ADIPLE T5", q: "¿Cuál es el objetivo final de toda la gestión de RRHH?", opts: ["Que el departamento de RRHH sea el más grande.", "Lograr una organización eficiente con personas satisfechas y productivas que aporten valor.", "Sustituir a todos por robots.", "No pagar sueldos."], ans: 1, exp: "La empresa triunfa cuando su gente está alineada con los objetivos y dispone de los medios y la motivación para alcanzarlos." },
// --- PREGUNTAS DE LA PLATAFORMA (MOODLE) ---
    { u: "ADIPLE T6", q: "A las personas que, sin haber sido dotadas de autoridad, tienen la capacidad de influenciar sobre los demás por su carisma y personalidad, se les denomina:", opts: ["Líderes", "Directores", "Jefes", "Mandos"], ans: 0, exp: "El liderazgo es una capacidad de influencia informal basada en el reconocimiento del grupo, a diferencia de la jefatura que es una autoridad impuesta jerárquicamente." },
    { u: "ADIPLE T6", q: "¿Cuál de las siguientes es una tendencia actual relativa a la comunicación interna?", opts: ["Motor de digitalización", "Employer Branding", "Apps internas", "Todas son correctas"], ans: 3, exp: "Las empresas modernas utilizan herramientas digitales y estrategias de marca empleador para mejorar la comunicación, el compromiso y la transparencia con sus trabajadores." },
    { u: "ADIPLE T6", q: "El estilo de liderazgo en el que el líder interviene solo cuando lo cree conveniente, dejando máxima libertad a sus empleados y controlando lo mínimo imprescindible, se denomina:", opts: ["Liderazgo laissez faire", "Liderazgo democrático", "Liderazgo paternalista", "Liderazgo visionario"], ans: 0, exp: "El estilo laissez-faire (dejar hacer) delega la toma de decisiones en el equipo, interviniendo el líder únicamente cuando es estrictamente necesario o solicitado." },
    { u: "ADIPLE T6", q: "El estilo de liderazgo en el que el líder toma todas las decisiones, no delega y ejerce un control estricto sobre los subordinados se denomina:", opts: ["Liderazgo democrático", "Liderazgo autocrático", "Liderazgo liberal", "Liderazgo transformacional"], ans: 1, exp: "En el liderazgo autocrático, el poder está centralizado en el líder, quien dicta las normas y los procesos sin consultar al grupo." },
    { u: "ADIPLE T6", q: "El proceso mediante el cual se transmite información, ideas o sentimientos de una persona a otra se llama:", opts: ["Liderazgo", "Motivación", "Comunicación", "Negociación"], ans: 2, exp: "La comunicación es la herramienta básica de interacción en la empresa, permitiendo la coordinación de tareas y la gestión de las relaciones interpersonales." },
    { u: "ADIPLE T6", q: "¿Qué nombre recibe el obstáculo que dificulta o impide la correcta recepción del mensaje en la comunicación?", opts: ["Canal", "Barrera", "Código", "Contexto"], ans: 1, exp: "Las barreras pueden ser físicas (ruido), semánticas (idioma), psicológicas (prejuicios) o fisiológicas, y distorsionan la intención original del emisor." },
    { u: "ADIPLE T6", q: "La pirámide de las necesidades humanas (fisiológicas, seguridad, sociales, estima y autorrealización) fue propuesta por:", opts: ["Douglas McGregor", "Frederick Herzberg", "Abraham Maslow", "David McClelland"], ans: 2, exp: "Maslow estableció que el ser humano tiene una jerarquía de necesidades que va satisfaciendo desde las más básicas hasta las de desarrollo personal." },
    { u: "ADIPLE T6", q: "La teoría que distingue entre factores higiénicos (que evitan la insatisfacción) y factores motivadores (que generan satisfacción) es de:", opts: ["Frederick Herzberg", "Douglas McGregor", "Abraham Maslow", "David McClelland"], ans: 0, exp: "Herzberg postuló que el sueldo o el ambiente son básicos (higiénicos), pero que lo que realmente motiva es el reconocimiento, la responsabilidad y el crecimiento." },
    { u: "ADIPLE T6", q: "La teoría X y la teoría Y, que describen dos formas opuestas de percibir el comportamiento de los trabajadores, pertenecen a:", opts: ["Maslow", "McGregor", "Herzberg", "Goleman"], ans: 1, exp: "McGregor describe la Teoría X (el trabajador es vago y necesita control) y la Teoría Y (el trabajador busca responsabilidades y es creativo)." },
    { u: "ADIPLE T6", q: "¿Cómo se denomina la capacidad de entender y gestionar las propias emociones y las de los demás?", opts: ["Inteligencia racional", "Inteligencia emocional", "Habilidad técnica", "Carisma"], ans: 1, exp: "Daniel Goleman popularizó este concepto, esencial para el liderazgo moderno, la empatía y la gestión de conflictos en equipos de trabajo." },

    // --- BLOQUE CUESTIONARIO DE AUTOEVALUACIÓN (70 PREGUNTAS) ---
    { u: "ADIPLE T6", q: "¿Qué diferencia a un 'Jefe' de un 'Líder'?", opts: ["El jefe tiene autoridad formal; el líder tiene autoridad moral y capacidad de influencia.", "El jefe siempre gana más dinero.", "El jefe no trabaja nada.", "No hay ninguna diferencia."], ans: 0, exp: "Se puede ser jefe sin ser líder, y líder sin tener un cargo oficial de jefe." },
    { u: "ADIPLE T6", q: "El 'Liderazgo Democrático' se caracteriza por:", opts: ["Mandar sin escuchar.", "Fomentar la participación del grupo en la toma de decisiones.", "Dejar que cada uno haga lo que quiera.", "No aparecer por la oficina."], ans: 1, exp: "El líder democrático busca el consenso, escucha opiniones y hace que el equipo se sienta parte de las soluciones." },
    { u: "ADIPLE T6", q: "¿Qué es el 'Feedback' en la comunicación?", opts: ["Un ruido molesto.", "La retroalimentación o respuesta del receptor que confirma la comprensión del mensaje.", "Una multa.", "El nombre del canal de radio."], ans: 1, exp: "Sin feedback no sabemos si el mensaje ha llegado correctamente o si ha habido un malentendido." },
    { u: "ADIPLE T6", q: "La 'Escucha Activa' implica:", opts: ["Oír ruidos de fondo.", "Prestar total atención al emisor, comprendiendo tanto el mensaje verbal como el no verbal.", "Interrumpir constantemente para preguntar.", "Mirar el móvil mientras nos hablan."], ans: 1, exp: "Escuchar activamente demuestra respeto y asegura que se capta toda la intención y emoción del interlocutor." },
    { u: "ADIPLE T6", q: "La 'Comunicación No Verbal' incluye:", opts: ["Solo las palabras escritas.", "Gestos, posturas, mirada, tono de voz y expresión facial.", "Hablar en inglés.", "Enviar correos electrónicos."], ans: 1, exp: "Más del 70% de lo que comunicamos se transmite a través del cuerpo y no de las palabras." },
    { u: "ADIPLE T6", q: "En la Pirámide de Maslow, la 'Autorrealización' se encuentra en:", opts: ["La base.", "La cúspide (nivel más alto).", "El segundo escalón.", "No aparece en la pirámide."], ans: 1, exp: "Es la necesidad de desarrollar el máximo potencial propio y alcanzar las metas personales de vida." },
    { u: "ADIPLE T6", q: "Según Herzberg, el 'Sueldo' se considera un factor:", opts: ["Motivador.", "Higiénico (básico).", "De autorrealización.", "Psicológico negativo."], ans: 1, exp: "El sueldo no motiva a largo plazo; simplemente evita que el trabajador esté descontento. Lo que motiva es el trabajo en sí." },
    { u: "ADIPLE T6", q: "¿Qué describe la 'Teoría Y' de McGregor?", opts: ["Que la gente odia trabajar.", "Que los trabajadores son creativos, buscan responsabilidades y se motivan por objetivos.", "Que hay que castigar a los empleados.", "Que solo importa el dinero."], ans: 1, exp: "Es la visión positiva del ser humano en el trabajo, base de las empresas modernas y tecnológicas." },
    { u: "ADIPLE T6", q: "La 'Empatía' es la habilidad de:", opts: ["Mandar con fuerza.", "Ponerse en el lugar del otro y comprender sus emociones.", "Saber mucho de matemáticas.", "Hablar muy rápido."], ans: 1, exp: "Es fundamental para un líder entender cómo se siente su equipo para poder motivarlo y apoyarlo adecuadamente." },
    { u: "ADIPLE T6", q: "¿Qué es la 'Asertividad'?", opts: ["Gritar para tener razón.", "Capacidad de expresar las propias ideas y sentimientos de forma clara y honesta sin agredir ni ser pasivo.", "Callarse siempre ante el jefe.", "Mentir para quedar bien."], ans: 1, exp: "Ser asertivo permite defender los derechos propios respetando los de los demás, clave en la negociación." },
    { u: "ADIPLE T6", q: "Un 'Conflicto Funcional' en la empresa es aquel que:", opts: ["Destruye la organización.", "Aporta beneficios, fomenta la creatividad y mejora los procesos tras su resolución.", "Es una pelea física.", "No tiene solución."], ans: 1, exp: "Los desacuerdos bien gestionados ayudan a detectar errores y a buscar soluciones innovadoras que antes no se veían." },
    { u: "ADIPLE T6", q: "La 'Motivación Intrínseca' proviene de:", opts: ["El sueldo y los premios externos.", "El placer y la satisfacción personal de realizar la propia tarea.", "Las amenazas del jefe.", "Los días de vacaciones."], ans: 1, exp: "Es la motivación más fuerte y duradera, ya que nace del interior del trabajador por su pasión por lo que hace." },
    { u: "ADIPLE T6", q: "El 'Liderazgo Situacional' sugiere que:", opts: ["Hay un estilo de líder perfecto para todo.", "El líder debe adaptar su estilo según la madurez y preparación del colaborador.", "Solo se puede liderar en situaciones de crisis.", "El líder nace, no se hace."], ans: 1, exp: "No se puede dirigir igual a un aprendiz novato que a un experto veterano con 20 años de experiencia." },
    { u: "ADIPLE T6", q: "¿Qué es el 'Engagement' laboral?", opts: ["Un tipo de contrato.", "El nivel de compromiso emocional e implicación del trabajador con su empresa.", "El horario de salida.", "El nombre del departamento de ventas."], ans: 1, exp: "Un empleado comprometido rinde más, falta menos y defiende a la empresa ante los clientes." },
    { u: "ADIPLE T6", q: "La 'Comunicación Descendente' fluye desde:", opts: ["Los operarios al director.", "La dirección hacia los subordinados (órdenes, objetivos).", "Entre compañeros de la misma sección.", "Desde los proveedores externos."], ans: 1, exp: "Sirve para informar sobre la estrategia, dar instrucciones de trabajo y evaluar resultados." },
    { u: "ADIPLE T6", q: "La 'Comunicación Horizontal' ocurre entre:", opts: ["Jefes y empleados.", "Personas del mismo nivel jerárquico o departamento.", "La empresa y los medios de comunicación.", "Nadie, es un término inventado."], ans: 1, exp: "Es vital para la coordinación entre departamentos (ej. producción y mantenimiento) y evita duplicar tareas." },
    { u: "ADIPLE T6", q: "¿Qué es un 'Rumor' en la comunicación interna?", opts: ["Una noticia oficial confirmada.", "Información no verificada que circula por canales informales.", "Un correo electrónico del gerente.", "El manual de calidad."], ans: 1, exp: "Los rumores suelen aparecer cuando la comunicación oficial es escasa o poco transparente, generando incertidumbre." },
    { u: "ADIPLE T6", q: "El 'Liderazgo Transformacional' busca:", opts: ["Mantener todo tal cual está.", "Inspirar y motivar a los empleados para lograr cambios positivos y resultados extraordinarios.", "Solo controlar los horarios.", "Castigar los errores pequeños."], ans: 1, exp: "Estos líderes cambian la cultura de la empresa y hacen que los trabajadores vean más allá de su propio interés." },
    { u: "ADIPLE T6", q: "¿Qué analiza la 'Teoría de las Expectativas'?", opts: ["El pasado del trabajador.", "Que la motivación depende de la creencia de que el esfuerzo llevará a una recompensa valorada.", "Solo el salario mínimo.", "La ropa de trabajo."], ans: 1, exp: "Si el trabajador piensa que por mucho que se esfuerce no va a conseguir nada, dejará de estar motivado." },
    { u: "ADIPLE T6", q: "Las 'Habilidades Sociales' permiten:", opts: ["Soldar piezas metálicas.", "Relacionarse de forma efectiva y armoniosa con los demás individuos.", "Arreglar motores eléctricos.", "Programar autómatas."], ans: 1, exp: "Son las llamadas 'soft skills' (habilidades blandas), críticas para el trabajo en equipo y la atención al cliente." },
    { u: "ADIPLE T6", q: "En la gestión del tiempo, las tareas 'Urgentes e Importantes' deben:", opts: ["Hacerse las últimas.", "Hacerse de forma inmediata (crisis, problemas apremiantes).", "Delegarse en otros.", "Desecharse."], ans: 1, exp: "Son las que presionan por plazo y tienen graves consecuencias si no se resuelven ya." },
    { u: "ADIPLE T6", q: "La 'Delegación' efectiva implica:", opts: ["Dar órdenes y no preguntar más.", "Asignar tareas y autoridad, pero manteniendo la responsabilidad final del resultado.", "Hacer el trabajo uno mismo.", "Echar la culpa al subordinado."], ans: 1, exp: "Delegar permite al líder centrarse en lo estratégico y desarrollar profesionalmente a su equipo." },
    { u: "ADIPLE T6", q: "Un 'Equipo de Trabajo' se diferencia de un 'Grupo' en que:", opts: ["En el equipo hay más gente.", "En el equipo existe un objetivo común y una responsabilidad compartida (sinergia).", "El grupo siempre trabaja en la misma mesa.", "No hay diferencia."], ans: 1, exp: "En un equipo, el resultado total es superior a la suma de las partes individuales." },
    { u: "ADIPLE T6", q: "¿Qué es el 'Coaching' empresarial?", opts: ["Un tipo de coche de empresa.", "Proceso de acompañamiento para ayudar a un profesional a alcanzar sus objetivos y desarrollar habilidades.", "Un examen de selección.", "El nombre del local físico."], ans: 1, exp: "El coach no da las respuestas, sino que mediante preguntas ayuda a que el coachee las encuentre por sí mismo." },
    { u: "ADIPLE T6", q: "La 'Resiliencia' es la capacidad de:", opts: ["Ser muy rígido.", "Adaptarse y superar situaciones adversas o periodos de crisis.", "Hacer muchas tareas a la vez.", "Hablar en público."], ans: 1, exp: "Un profesional resiliente aprende de los errores y vuelve a intentarlo con más fuerza tras un fracaso." },
    { u: "ADIPLE T6", q: "¿Qué son los 'Factores de Higiene' de Herzberg?", opts: ["Ducharse antes de entrar.", "Elementos externos al trabajo que si faltan causan insatisfacción (salario, seguridad, política empresa).", "El tipo de jabón del baño.", "Un premio de puntualidad."], ans: 1, exp: "Son necesarios para que no haya quejas, pero por sí solos no hacen que alguien trabaje con ilusión." },
    { u: "ADIPLE T6", q: "La 'Motivación Extrínseca' se basa en:", opts: ["El amor al arte.", "Recompensas externas como bonos, ascensos o evitar castigos.", "El aburrimiento.", "La genética."], ans: 1, exp: "Funciona bien para tareas rutinarias, pero es menos potente que la vocación interna." },
    { u: "ADIPLE T6", q: "Un 'Líder Paternalista' actúa:", opts: ["Como un tirano.", "Protegiendo a sus empleados como a hijos, pero limitando su autonomía y toma de decisiones.", "Como un amigo igualitario.", "Ignorando a todos."], ans: 1, exp: "Crea dependencia y aunque el clima puede ser amable, no fomenta el crecimiento profesional del equipo." },
    { u: "ADIPLE T6", q: "La 'Sinergia' en un equipo significa que:", opts: ["Todos se llevan mal.", "El resultado conjunto es mayor que la suma de los esfuerzos individuales (1+1=3).", "Todos piensan exactamente igual.", "El líder hace todo el trabajo."], ans: 1, exp: "Es el objetivo de todo equipo: combinar talentos distintos para lograr lo que nadie podría solo." },
    { u: "ADIPLE T6", q: "¿Qué es la 'Inteligencia Intrapersonal'?", opts: ["Entender a los vecinos.", "Capacidad de conocerse a uno mismo, las propias emociones y metas.", "Saber mucho de geografía.", "Ser muy rápido corriendo."], ans: 1, exp: "Es la base de la autogestión y el autocontrol emocional." },
    { u: "ADIPLE T6", q: "Un 'Conflicto Interpersonal' ocurre entre:", opts: ["Dos empresas rivales.", "Dos o más personas dentro de la organización.", "Una persona y sus propios pensamientos.", "El operario y la máquina."], ans: 1, exp: "Suelen deberse a choques de personalidad, fallos de comunicación o competencia por recursos." },
    { u: "ADIPLE T6", q: "La 'Negociación Ganar-Ganar' (Win-Win) busca:", opts: ["Engañar al otro.", "Un acuerdo que satisfaga los intereses de ambas partes de forma duradera.", "Que el más fuerte gane todo.", "No llegar a ningún acuerdo."], ans: 1, exp: "Es la base de las relaciones comerciales y laborales sanas a largo plazo." },
    { u: "ADIPLE T6", q: "¿Qué es el 'Empowerment'?", opts: ["Dar electricidad a las máquinas.", "Dotar a los empleados de autoridad y autonomía para tomar decisiones sobre su propio trabajo.", "Comprar ordenadores nuevos.", "Poner cámaras de vigilancia."], ans: 1, exp: "Aumenta la velocidad de respuesta y hace que el trabajador se sienta más valorado y responsable." },
    { u: "ADIPLE T6", q: "En la comunicación, el 'Código' es:", opts: ["Un número secreto.", "El sistema de signos y reglas usado para elaborar el mensaje (ej. el idioma).", "El cable del teléfono.", "El precio del producto."], ans: 1, exp: "Si emisor y receptor no comparten el mismo código (idioma o tecnicismos), la comunicación falla." },
    { u: "ADIPLE T6", q: "La 'Asertividad' en la crítica consiste en:", opts: ["No decir nada malo nunca.", "Señalar el error de forma constructiva, basándose en hechos y no en ataques personales.", "Gritar delante de todos.", "Mandar un correo anónimo."], ans: 1, exp: "Ayuda a mejorar el rendimiento del equipo sin dañar la autoestima de las personas." },
    { u: "ADIPLE T6", q: "Un líder 'Visionario' se caracteriza por:", opts: ["Llevar gafas graduadas.", "Tener una idea clara del futuro y ser capaz de inspirar al equipo para alcanzarla.", "Vivir en el pasado.", "No tener planes."], ans: 1, exp: "Son líderes que mueven a las personas hacia sueños compartidos (ej. Steve Jobs)." },
    { u: "ADIPLE T6", q: "¿Qué analiza la 'Teoría de la Equidad'?", opts: ["Que todos cobren lo mismo.", "Que los trabajadores comparan su esfuerzo/recompensa con el de sus compañeros.", "Solo los derechos de las mujeres.", "La justicia en los tribunales."], ans: 1, exp: "Si un trabajador siente que hace más que otro pero cobra menos, su motivación caerá en picado." },
    { u: "ADIPLE T6", q: "La 'Comunicación Ascendente' sirve para:", opts: ["Dar órdenes de despido.", "Que los subordinados envíen sugerencias, quejas o informes a sus superiores.", "Vender a los clientes.", "Hablar con el Estado."], ans: 1, exp: "Permite a la gerencia conocer la realidad de la planta y los problemas que tienen los trabajadores." },
    { u: "ADIPLE T6", q: "¿Qué es el 'Liderazgo Transaccional'?", opts: ["Un intercambio de favores ilegales.", "Basado en un intercambio (transacción) de premios o castigos según el cumplimiento de tareas.", "No usar dinero.", "Mandar solo por teléfono."], ans: 1, exp: "Es el liderazgo clásico de 'Si haces esto bien, te doy este bono'." },
    { u: "ADIPLE T6", q: "La 'Habilidad Técnica' de un directivo es:", opts: ["Saber liderar grupos.", "Conocimiento y pericia en los procesos y herramientas específicas de su área (ej. ingeniería).", "Caer bien a la gente.", "Hablar en público."], ans: 1, exp: "Es más importante en mandos intermedios y jefes de taller que en el director general." },
    { u: "ADIPLE T6", q: "El 'Clima Laboral' se mide habitualmente mediante:", opts: ["Un termómetro.", "Encuestas anónimas de satisfacción y entrevistas de clima.", "Mirando las caras de la gente.", "Por el número de ventas."], ans: 1, exp: "Permite detectar problemas ocultos antes de que estallen en huelgas o bajas masivas." },
    { u: "ADIPLE T6", q: "¿Qué significa ser un 'Líder Facilitador'?", opts: ["Hacer el trabajo de los demás.", "Aquel que elimina obstáculos para que su equipo pueda trabajar con eficiencia.", "Regalar aprobado a todos.", "No poner normas."], ans: 1, exp: "Su rol es dar los recursos y el apoyo necesario para que el equipo brille." },
    { u: "ADIPLE T6", q: "La 'Pirámide de Maslow' tiene:", opts: ["3 niveles.", "5 niveles (fisiológicas, seguridad, sociales, estima y autorrealización).", "10 niveles.", "Un solo nivel."], ans: 1, exp: "Es el modelo más conocido para entender qué mueve a las personas en la vida y el trabajo." },
    { u: "ADIPLE T6", q: "La 'Comunicación Informal' en la empresa:", opts: ["Es obligatoria por ley.", "Surge de forma espontánea entre los trabajadores fuera de los canales oficiales.", "No existe en empresas grandes.", "Es siempre negativa."], ans: 1, exp: "Incluye las charlas en el comedor o el café; es muy rápida pero puede generar rumores." },
    { u: "ADIPLE T6", q: "¿Qué es el 'Burn-out'?", opts: ["Un incendio en la fábrica.", "Síndrome de agotamiento emocional y estrés crónico en el trabajo.", "Quedarse sin batería en el móvil.", "Tener mucha fiebre."], ans: 1, exp: "Es un riesgo laboral que el departamento de RRHH debe vigilar para evitar bajas prolongadas." },
    { u: "ADIPLE T6", q: "La 'Comunicación Asertiva' evita:", opts: ["Tanto la pasividad (no decir nada) como la agresividad (atacar).", "Hablar con los jefes.", "Gastar dinero en sellos.", "Que la gente se ría."], ans: 0, exp: "Busca un equilibrio donde se dice la verdad con firmeza pero con educación." },
    { u: "ADIPLE T6", q: "Un 'Grupo de Trabajo' se caracteriza por:", opts: ["Tener una meta común fuerte.", "Individuos que trabajan de forma independiente con responsabilidad individual.", "Compartir todas las tareas.", "No tener jefe."], ans: 1, exp: "A diferencia del equipo, en el grupo cada uno hace lo suyo y se lo entrega al siguiente." },
    { u: "ADIPLE T6", q: "El 'Liderazgo Ético' se basa en:", opts: ["Ganar dinero rápido.", "Principios morales, integridad y respeto por los derechos de todos los involucrados.", "Mandar a los amigos.", "Ser el más listo de la clase."], ans: 1, exp: "Genera confianza a largo plazo con empleados, clientes y sociedad." },
    { u: "ADIPLE T6", q: "¿Qué es el 'Capital Psicológico'?", opts: ["Lo que cuesta el psicólogo.", "Conjunto de estados positivos como esperanza, optimismo y resiliencia en el trabajo.", "Un examen de inteligencia.", "La locura de los jefes."], ans: 1, exp: "Tener un equipo con mentalidad positiva mejora la resolución de problemas en un 20%." },
    { u: "ADIPLE T6", q: "La 'Habilidad Conceptual' de un líder permite:", opts: ["Dibujar planos técnicos.", "Ver la empresa como un todo y entender cómo se relacionan las distintas partes.", "Hacer cálculos de IVA.", "Arreglar un PLC."], ans: 1, exp: "Es vital para la alta dirección: permite planificar estrategias generales." },
    { u: "ADIPLE T6", q: "El 'Reconocimiento' como factor motivador consiste en:", opts: ["Pagar el salario mínimo.", "Valorar y agradecer explícitamente el buen trabajo y el esfuerzo de los empleados.", "Hacer fotos para el carnet.", "Identificar a los ladrones."], ans: 1, exp: "Sentirse valorado es una de las necesidades más profundas del ser humano tras las básicas." },
    { u: "ADIPLE T6", q: "¿Qué describe la 'Teoría X' de McGregor?", opts: ["Que a la gente le encanta esforzarse.", "Que el trabajador medio es perezoso, evita responsabilidades y necesita ser controlado.", "Que los robots son mejores.", "Que no existen jefes."], ans: 1, exp: "Es la visión pesimista que lleva a estilos de mando autoritarios y de vigilancia extrema." },
    { u: "ADIPLE T6", q: "Un líder con 'Habilidades Comunicativas' sabe:", opts: ["Hablar 5 idiomas perfectamente.", "Transmitir ideas con claridad, escuchar y persuadir positivamente.", "Hablar durante horas sin decir nada.", "Escribir libros de poemas."], ans: 1, exp: "La comunicación es el puente que une al líder con su equipo; sin ella no hay liderazgo." },
    { u: "ADIPLE T6", q: "El clima laboral influye directamente en la 'Rotación de Personal', que es:", opts: ["El cambio de turno de los trabajadores.", "La frecuencia con la que los empleados abandonan la empresa y son sustituidos.", "Que los trabajadores den vueltas por la fábrica.", "El horario de apertura y cierre."], ans: 1, exp: "Un mal clima hace que la gente se vaya, lo que cuesta mucho dinero en formación y selección de nuevos empleados." },
    { u: "ADIPLE T6", q: "¿Qué es la 'Intranet'?", opts: ["El internet de toda la vida.", "Una red privada interna de la empresa para compartir información entre empleados.", "Un virus informático.", "Una marca de ordenadores."], ans: 1, exp: "Permite colgar nóminas, manuales, noticias y tablones de anuncios de forma segura." },
    { u: "ADIPLE T6", q: "La 'Responsabilidad' como factor motivador implica:", opts: ["Tener la culpa de todo lo malo.", "Dar al trabajador autonomía y control sobre sus propias tareas.", "Aumentar el número de horas de vigilancia.", "Obligar al trabajador a firmar documentos peligrosos."], ans: 1, exp: "Sentirse dueño de su trabajo motiva mucho más que seguir órdenes mecánicas." },
    { u: "ADIPLE T6", q: "El objetivo final de desarrollar habilidades interpersonales es:", opts: ["Ser el más popular de la oficina.", "Construir relaciones profesionales sólidas que beneficien tanto al individuo como a la organización.", "Evitar trabajar lo máximo posible.", "Consigue que el jefe nos invite a cenar."], ans: 1, exp: "Las empresas son personas; si las personas se llevan bien y se comunican, la empresa funciona." },
    { u: "ADIPLE T6", q: "Un líder 'Carismático' atrae a los demás por:", opts: ["Su gran sueldo.", "Su personalidad, entusiasmo y capacidad de generar admiración.", "Su fuerza física.", "Su parentesco con el dueño."], ans: 1, exp: "El carisma facilita que la gente siga al líder de forma voluntaria y apasionada." },
    { u: "ADIPLE T6", q: "¿Qué es la 'Cultura de la Innovación'?", opts: ["Pintar la fachada de moderno.", "Ambiente donde se premia la creatividad y no se castiga el error honesto al probar cosas nuevas.", "Comprar una máquina de café nueva.", "Cambiar de logo cada mes."], ans: 1, exp: "Sin esta cultura, los trabajadores tienen miedo a fallar y nunca proponen mejoras." },
    { u: "ADIPLE T6", q: "¿Cuál es el objetivo final de estudiar liderazgo y motivación?", opts: ["Aprender a mandar.", "Ser capaz de gestionar equipos humanos de forma eficiente, logrando los objetivos y el bienestar del grupo.", "Pagar menos sueldos.", "Sustituir a los trabajadores."], ans: 1, exp: "Un buen mando industrial debe saber tanto de máquinas como de personas para que la planta sea productiva y segura." }
];
